import { useState, useEffect, useMemo, useRef } from "react";
import { supabase } from "./supabaseClient";

// ---- Perks dataset (109 perks, real in-game icons) ----
const PERKS = [{"id": "leftBehind", "name": "Left Behind", "side": "survivor", "img": "data:image/png;base64,", "desc": "Débloque le potentiel de repérage d’aura d’une personne. Si vous êtes le dernier survivant lors de la partie, vous pouvez voir l’aura de la trappe jusqu’à 32 mètres.", "fr": "Abandonné", "descEn": "Unlocks potential in one's aura reading ability. If you are the last Survivor remaining in the trial, you can see the aura of the Hatch within a 32 meter range.", "descEs": "Permite percibir auras. Si eres el último superviviente con vida en la partida, podrás ver el aura de la trampilla a una distancia de 32 metros.", "es": "Abandonado a tu suerte", "charEn": "William \"Bill\" Overbeck", "charFr": "William « Bill » Overbeck", "charEs": "William \"Bill\" Overbeck"},{"id": "wereGonnaLiveForever", "name": "We're Gonna Live Forever", "side": "survivor", "img": "data:image/png;base64,", "desc": "Le peu d'amis que vous avez méritent la meilleure protection possible. Lorsque vous soignez un autre survivant en état critique, votre vitesse de soins est augmentée de 100 %. Gagnez un jeton en effectuant l'une des actions suivantes :Effectuer un décrochage sécuritaireEncaisser un coup pour protéger un survivantSecourir un survivant en étourdissant le tueur avec une paletteSecourir un survivant en aveuglant le tueur avec une lampe de pocheQuand la deuxième fonction de cette compétence est active, soigner un autre survivant en état critique leur accorde Endurance pendant 100 secondes et désactive la fonction secondaire. Endurance empêche qu’un survivant soit abattu et lui inflige Blessure profonde à la place..", "fr": "Nous vivrons éternellement", "descEn": "Your few friends deserve the best protection. When healing another Survivor in the dying state, your healing speed is increased by 100%. Additionally, performing any of the following actions activates this perk's secondary function:Perform a Safe Hook RescueTake a hit to protect a SurvivorRescue a Survivor by stunning the Killer with a palletRescue a Survivor by blinding the Killer with a FlashlightWhen this perk's secondary function is active, healing another Survivor out of the dying state grants them Endurance for 100 seconds and deactivates the secondary function. Endurance prevents a Survivor from being downed, inflicting Deep Wound instead.", "descEs": "Tus amigos merecen la máxima protección. Cuando cures a un superviviente agonizante, tu velocidad de curación aumenta un 100 %. Además, cualquiera de las siguientes acciones activa la función secundaria de esta habilidad:Rescate de gancho seguroSufrir un golpe por proteger a un supervivienteRescatar a un superviviente aturdiendo al asesino con un paléRescatar a un superviviente cegando al asesino con una linternaCuando esté activa la función secundaria de esta habilidad, si curas a otro superviviente en estado agonizante, obtendrás Resistencia durante 100 segundos y desactiva la función secundaria. Resistencia impide que se derribe a un superviviente y le causa Herida profunda.", "es": "Vamos a vivir para siempre", "charEn": "David King", "charFr": "David King", "charEs": "David King"},{"id": "noMither", "name": "No Mither", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous êtes affecté par l’effet de statut Brisé pendant toute la durée de la partie. Votre sang épais coagule presque instantanément. Vous ne laissez pas de flaques de sang.Les gémissements de douleur dus aux blessures sont toujours réduits de 75 %.Votre vitesse de récupération augmente de 25 % et vous pouvez récupérer pleinement d’un état critique.", "fr": "Pas de pleurnicherie", "descEn": "You are affected by the Broken status effect for the duration of the trial. Your thick blood coagulates practically instantly. You don't leave pools of blood.Grunts of pain caused by injuries are reduced by 75% at any time.Your recovery speed is increased by 25% and you can completely recover from the dying state.", "descEs": "Sufres el efecto de estado Desesperanza durante toda la partida. Tu sangre espesa se coagula prácticamente al instante. No dejas charcos de sangre.Los gruñidos de dolor causados por las heridas se reducen un 75 % en todo momento.La velocidad de recuperación aumenta un 25 % y te permite recuperarte completamente del estado agonizante.", "es": "Me la pela", "charEn": "David King", "charFr": "David King", "charEs": "David King"},{"id": "soleSurvivor", "name": "Sole Survivor", "side": "survivor", "img": "data:image/png;base64,", "desc": "Tandis que vos compagnons succombent au tueur les uns après les autres, l'isolation vous dissimule et les capacités de repérage d’aura du tueur s'en trouvent perturbées. Chaque fois qu’un survivant est tué ou sacrifié, vous gagnez un jeton. Pour chaque jeton, votre aura est invisible pour le tueur dans un rayon maximal de 24 mètres. Lorsque vous êtes le dernier survivant en vie :Vous gagnez 75 % de vitesse d'action en réparant des générateurs.Vous gagnez 50 % de vitesse d'action en ouvrant une porte de sortie ou la trappe. Augmente vos chances d’être l’obsession du tueur.Le tueur ne peut être obsédé que par un seul survivant à la fois.", "fr": "Unique survivant", "descEn": "As more of your friends fall to the Killer, you become shrouded in isolation and the Killer's aura-reading abilities towards you are disrupted. Every time a fellow Survivor is killed or sacrificed, gain a token. For each token, your aura cannot be read by The Killer within a max range of 24 meters. When you're the last Survivor alive:Gain 75% action speed when repairing generators.Gain 50% action speed while opening an exit gate or the Hatch. Increases your chances of being The Killer's Obsession.The Killer can only be obsessed with one Survivor at a time.", "descEs": "A medida que tus amigos caigan en manos del asesino, te embargará la soledad y la capacidad del asesino para detectar tu aura se verá perturbada. Cada vez que un superviviente sea asesinado o sacrificado, obtendrás un distintivo. Por cada distintivo, el asesino no podrá detectar tu aura a una distancia máxima de 24 metros. Si eres el último superviviente con vida:Obtienes un 75 % de velocidad de acción al reparar generadores.Obtienes un 50 % de velocidad de acción al abrir una puerta de salida o la trampilla. Aumenta las probabilidades de que te conviertas en la obsesión del asesino.El asesino no puede obsesionarse con más de un superviviente.", "es": "Solo quedo yo", "charEn": "Laurie Strode", "charFr": "Laurie Strode", "charEs": "Laurie Strode"},{"id": "objectOfObsession", "name": "Object of Obsession", "side": "survivor", "img": "data:image/png;base64,", "desc": "Un lien surnaturel vous unit au tueur. Quand votre aura lui est révélée, vous voyez la sienne et vous gagnez un bonus de 6 % à la vitesse de guérison, de réparation et de purification. Si vous êtes l’obsession, votre aura est révélée au tueur pendant 3 secondes toutes les 30 secondes. Augmente vos chances de devenir l’obsession.", "fr": "Objet d'obsession", "descEn": "A supernatural bond links you to the Killer. Whenever your aura is revealed to the Killer, the Killer's aura becomes visible to you and you gain a 6% bonus to healing, repairing and cleansing speed. If you are the Obsession, your aura is revealed to the Killer for 3 seconds once every 30 seconds. Increases your chances of being the Obsession.", "descEs": "Un vínculo sobrenatural te une al asesino. Cuando se muestra tu aura al asesino, también podrás ver la suya y obtienes un 6 % adicional a la velocidad de curación, reparación y purificación. Si eres la obsesión, tu aura se mostrará al asesino durante 3 segundos una vez cada 30 segundos. Aumenta las probabilidades de que seas la obsesión del asesino.", "es": "Objeto de obsesión", "charEn": "Laurie Strode", "charFr": "Laurie Strode", "charEs": "Laurie Strode"},{"id": "upTheAnte", "name": "Up the Ante", "side": "survivor", "img": "data:image/png;base64,", "desc": "Tout se terminera bien, vous le sentez. Votre confiance en vous ravive l'espoir de ceux qui se trouvent autour de vous. Confère 3 % de bonus de chance à tous les survivants, pour chaque survivant encore en vie.", "fr": "Augmenter la mise", "descEn": "All will be well in the end; you just know it. Your confidence strengthens the feeling of hope for those around you. For each other Survivor still alive, grant a 3% bonus of luck to all remaining Survivors.", "descEs": "Al final todo saldrá bien, simplemente lo sabes. Tu confianza fortalece la esperanza de los que te rodean. Por cada superviviente vivo, otorga un 3 % de suerte adicional al resto de supervivientes.", "es": "Subir las apuestas", "charEn": "Ace Visconti", "charFr": "Ace Visconti", "charEs": "Ace Visconti"},{"id": "aceInTheHole", "name": "Ace in the Hole", "side": "survivor", "img": "data:image/png;base64,", "desc": "Dame Fortune semble vous choyer en permanence. Quand vous trouvez un objet dans un coffre, il y a 100 % de chances qu’un accessoire très rare ou inférieur y soit attaché. 50 % de chances de trouver un accessoire insolite ou inférieur. En vous échappant, conservez tous les accessoires de votre objet.", "fr": "Atout dans la manche", "descEn": "Lady Luck always seems to be throwing something good your way. When retrieving an item from a chest, there is a 100% chance that a Very Rare (or lower) add-on will be attached to it. 50% chance of finding an add-on of Uncommon rarity (or lower). When escaping, keep any add-ons your item has.", "descEs": "Parece que la suerte siempre está de tu parte. Al sacar un objeto de un cofre, hay un 100 % de probabilidades de que lleve un accesorio muy raro (o inferior) y un 50 % de probabilidades de que lleve un accesorio poco común (o inferior). Al escapar, conservas cualquier accesorio que tenga tu objeto.", "es": "As en la manga", "charEn": "Ace Visconti", "charFr": "Ace Visconti", "charEs": "Ace Visconti"},{"id": "technician", "name": "Technician", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous êtes capable de manier des machines avec la plus grande précision et attention. Le bruit occasionné par vos réparations et la distance à laquelle ils peuvent être perçus sont réduits de 8 mètres. Si le test d'habileté pour la réparation échoue, il y a 3 % de chances que l'explosion du générateur soit évitée.", "fr": "Technicien", "descEn": "You are apt at handling machinery with the greatest care and precision. The noises caused by your repairs and their hearing distance are reduced by 8 meters. On a failed repair Skill Check, there is a 3% chance the generator explosion will be prevented.", "descEs": "Se te da muy bien manejar máquinas con precisión y cuidado. Tus reparaciones hacen menos ruido y la distancia desde la que se oyen se reduce 8 metros. Si fallas una prueba de habilidad de reparación, tienes un 3 % de probabilidad de que el generador no explote.", "es": "Pericia técnica", "charEn": "Feng Min", "charFr": "Feng Min", "charEs": "Feng Min"},{"id": "alert", "name": "Alert", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vos sens aiguisés sont en alerte. Lorsque le tueur casse quelque chose, il vous est révélé pendant 5 secondes.", "fr": "Vigilant", "descEn": "Your acute senses are on high alert. When the Killer performs a break action, the Killer is revealed to you for 5 seconds.", "descEs": "Tus agudos sentidos están en alerta máxima. Cuando el asesino rompe algo, puedes verlo durante 5 segundos.", "es": "Alerta", "charEn": "Feng Min", "charFr": "Feng Min", "charEs": "Feng Min"},{"id": "wakeUp", "name": "Wake Up!", "side": "survivor", "img": "data:image/png;base64,", "desc": "Débloque le potentiel de repérer les auras. Une fois que tous les générateurs ont été activés, les portes de sortie vous sont révélées à une portée de 128 mètres. Votre aura est révélée aux autres survivants jusqu'à 128 mètres lorsque vous ouvrez les portes de sortie. Lorsque Debout ! est actif, vous ouvrez les portes de sortie 15 % plus rapidement.", "fr": "Debout !", "descEn": "Unlocks potential in one's aura reading ability. Once all generators are powered, exit gates are revealed to you within a 128 meter range. While opening the exit gates, reveal your aura to other Survivors up to 128 meters. While Wake Up! is active, you open the exit gates 15% faster.", "descEs": "Permite percibir auras. Cuando se repare el último generador, verás las puertas de salida dentro de un radio de 128 metros. Mientras abres una puerta, el resto de supervivientes verá tu aura dentro de una distancia de 128 metros. Mientras ¡Despierta! esté activo, abrirás las puertas de salida un 15 % más rápido.", "es": "¡Despierta!", "charEn": "Quentin Smith", "charFr": "Quentin Smith", "charEs": "Quentin Smith"},{"id": "pharmacy", "name": "Pharmacy", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous avez un don pour trouver des médicaments. En cas de blessure, Pharmacie s'active. Pendant qu'elle est active : Vous déverrouillez les coffres 80 % plus rapidement.La distance à laquelle le bruit d'ouverture du coffre peut être perçu est réduite de 8 mètres. Pharmacie vous garantit une trousse de soins d’urgence lorsque l'interaction est complétée.", "fr": "Pharmacie", "descEn": "You have a knack for finding medicine. When injured, Pharmacy activates. While active: Unlocking chests is 80% faster.The hearing distance for noises from unlocking chests are reduced by 8 meters.Pharmacy guarantees an Emergency Med-kit upon completing the interaction.", "descEs": "Se te da bien encontrar medicinas. Si te han herido, se activa Farmacia. Mientras dure su efecto: Desbloqueas cofres un 80 % más rápido.La distancia desde la que se oyen se reduce en 8 metros.Farmacia te garantiza un botiquín de emergencia tras completar la interacción.", "es": "Farmacia", "charEn": "Quentin Smith", "charFr": "Quentin Smith", "charEs": "Quentin Smith"},{"id": "vigil", "name": "Vigil", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous veillez sur vos amis même dans les situations les plus rudes. Vous, et vos alliés dans un rayon de 8 mètre(s), récupérez des effets de statut Aveuglement, Brisé, Épuisement, À découvert, Hémorragie, Entrave et Inconscient 30 % plus rapidement. Une fois hors de portée, cet effet dure pendant 15 secondes.", "fr": "Veillée", "descEn": "You look over your friends even in dire situations. You and your allies within a 8 meter range recover from the Blindness, Broken, Exhausted, Exposed, Hemorrhage, Hindered and Oblivious status effects 30% faster. Once out of range, this effect persists for 15 seconds.", "descEs": "Cuidas de tus amigos hasta en las situaciones más extremas. Tanto tú como tus aliados en un radio de 8 metros os recuperáis de los efectos de estado Ceguera, Desesperanza, Agotamiento, Vulnerabilidad, Hemorragia, Entorpecimiento e Inconsciencia un 30 % más rápido. Una vez fuera de alcance, el efecto seguirá activo durante 15 segundos.", "es": "Vigilia", "charEn": "Quentin Smith", "charFr": "Quentin Smith", "charEs": "Quentin Smith"},{"id": "tenacity", "name": "Tenacity", "side": "survivor", "img": "data:image/png;base64,", "desc": "Rien ne vous arrête. Votre incroyable ténacité dans les situations difficiles vous permet de ramper 50 % plus vite tout en récupérant. Les gémissements de douleur en état critique sont réduit de 75 %.", "fr": "Ténacité", "descEn": "There is nothing stopping you. Your ferocious tenacity in dire situations allows you to crawl 50% faster and recover at the same time. Grunts of pain while in the dying state are reduced by 75%.", "descEs": "Nada puede detenerte. Tu feroz tenacidad en las situaciones más extremas te permite arrastrarte un 50 % más rápido y recuperarte al mismo tiempo. Los gruñidos de dolor en estado agonizante se reducen un 75 %.", "es": "Tenacidad", "charEn": "Detective Tapp", "charFr": "Inspecteur Tapp", "charEs": "Detective Tapp"},{"id": "stakeOut", "name": "Stake Out", "side": "survivor", "img": "data:image/png;base64,", "desc": "Votre détermination augmente quand vous vous rapprochez du tueur. À chaque fois que vous passez 15 secondes dans le rayon de terreur du tueur sans être poursuivi, vous gagnez un jeton (jusqu'à 4 jetons maximum). Quand En planque bénéficie d'au moins 1 jeton, les bons tests d'habileté sont considérés comme d'excellents tests d'habileté, ils consomment 1 jeton et octroient un bonus supplémentaire d'1 % à la progression de réparation du générateur.", "fr": "En planque", "descEn": "Getting close to the Killer fills you with determination. For each 15 seconds you are standing within the Killer Terror Radius and not in a chase, you gain a token up to a maximum of 4 tokens. When Stake Out has at least 1 token, good Skill Checks are considered great Skill Checks, consume 1 token, and grant an additional 1% bonus to generator repair progress.", "descEs": "Estar cerca del asesino te llena de determinación. Por cada 15 segundos que pases dentro del radio de terror del asesino sin que te esté persiguiendo, consigues un distintivo, hasta un máximo de 4. Cuando Bajo vigilancia tenga al menos 1 distintivo, la siguiente prueba de habilidad superada se considerará excelente, consumirá 1 distintivo y otorgará una bonificación adicional del 1 % en el progreso de reparación de los generadores.", "es": "Bajo vigilancia", "charEn": "Detective Tapp", "charFr": "Inspecteur Tapp", "charEs": "Detective Tapp"},{"id": "danceWithMe", "name": "Dance With Me", "side": "survivor", "img": "data:image/png;base64,", "desc": "Lors d'un saut d'obstacle rapide ou si vous quittez un casier en vitesse, vous ne laissez pas de marques d'éraflure pendant 3 secondes. Danse avec moi a un temps de récupération de 40 secondes.", "fr": "Danse avec moi", "descEn": "When performing a fast vault or leaving a locker in a sprint, you leave no scratch marks for 3 seconds. Dance With Me has a cooldown of 40 seconds.", "descEs": "Cuando das un salto rápido o sales corriendo de una taquilla, no dejas marcas de arañazos durante 3 segundos. Baila conmigo tiene un tiempo de recarga de 40 segundos.", "es": "Baila conmigo", "charEn": "Kate Denson", "charFr": "Kate Denson", "charEs": "Kate Denson"},{"id": "boilOver", "name": "Boil Over", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous êtes un battant et faites votre possible pour vous sortir des griffes du tueur. Les effets de votre lutte contre le tueur augmentent de 100 %. Vous obscurcissez la capacité du tueur à voir l’aura des crochets dans un rayon de 16 mètres. Vous gagnez 33 % sur votre progression de gigotement quand le tueur tombe de haut.", "fr": "Effusion", "descEn": "You are a battler and do everything to escape a foe's grasp. Your struggling effects on The Killer are increased by 100%. You obscure The Killer's ability to see hook auras within 16 meters. You gain 33 % of current wiggling progress when the Killer drops from great heights.", "descEs": "Tienes un espíritu luchador y haces todo por zafarte del enemigo. Tus efectos de forcejeo contra el asesino aumentan en un 100 %. Nublas la habilidad del asesino para ver auras de gancho en un radio de 16 metros. Obtienes un 33 % del progreso de forcejeo actual cuando el asesino caiga desde una gran altura.", "es": "Arrebato", "charEn": "Kate Denson", "charFr": "Kate Denson", "charEs": "Kate Denson"},{"id": "diversion", "name": "Diversion", "side": "survivor", "img": "data:image/png;base64,", "desc": "Compétence pouvant être activée. Se trouver dans le rayon de terreur du tueur lorsqu’il n’y a pas de poursuite pendant 30 secondes active Diversion. Une fois Diversion activée, appuyez sur le bouton de capacité active en étant accroupi et immobile afin de jeter un caillou à une distance de 20 mètres, qui crée une distraction pour le tueur. Le chrono de la compétence est réinitialisé après l’activation de la capacité. Détail de la distraction : alerte par une notification sonore et des marques d’éraflure", "fr": "Diversion", "descEn": "Activatable perk. Being within the Killer's Terror Radius while not in a chase for 30 seconds activates Diversion. Once Diversion is activated, press the Active Ability button while crouched and motionless to throw a pebble, which creates a distraction for The Killer at a distance of 20 meters. The perk timer resets once the ability has been activated. The distraction consists of: A loud noise notificationScratch marks", "descEs": "Habilidad activable. Distracción se activa cuando permaneces 30 segundos en el radio de terror del asesino sin que te persiga. Cuando Distracción esté activa, pulsa el botón de la habilidad activa mientras estás inmóvil y de cuclillas para lanzar una piedra que produce una distracción para el asesino a una distancia de 20 metros. El temporizador de la habilidad se reinicia tras activarse. La distracción consiste en: Una notificación de ruido intensoMarcas de arañazos", "es": "Distracción", "charEn": "Adam Francis", "charFr": "Adam Francis", "charEs": "Adam Francis"},{"id": "deliverance", "name": "Deliverance", "side": "survivor", "img": "data:image/png;base64,", "desc": "Après avoir réalisé le décrochage sécuritaire d’un autre survivant, Libération s’active. Vous avez désormais 100 % de chances de vous décrocher vous-même lors d’une tentative d’évasion. Une Libération du crochet réussie déclenche l’effet de statut Brisé pendant 60 secondes.", "fr": "Libération", "descEn": "After performing a safe hook rescue on another Survivor, Deliverance activates. You now have a 100% chance of unhooking yourself during the escape attempt. A successful Deliverance from the hook triggers the Broken status effect for 60 seconds.", "descEs": "La habilidad Liberación se activa tras llevar a cabo un rescate de gancho seguro a otro superviviente. Pasas a tener un 100 % de probabilidades de desengancharte cuando lo intentes. Al hacerlo, se activará el efecto de estado Desesperanza durante 60 segundos.", "es": "Liberación", "charEn": "Adam Francis", "charFr": "Adam Francis", "charEs": "Adam Francis"},{"id": "autodidact", "name": "Autodidact", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous commencez la partie avec -5 % de malus de progression pour les tests d’habileté de guérison des survivants. Chaque fois que vous réussissez un test d’habileté en soignant un survivant, vous recevez un jeton, jusqu’à un maximum de 25 jetons. Chaque jeton vous confère +15 % de progression bonus. Les tests d’habileté excellents ne peuvent pas être réalisés lorsque vous utilisez Autodidacte.Autodidacte n’est pas actif lorsque vous utilisez une trousse de soins.", "fr": "Autodidacte", "descEn": "You start the trial with a -5% progress penalty for Skill Checks to heal Survivors. For every successful Skill Check while healing a Survivor, you receive a token up to a maximum of 25 tokens. Each token grants you a +15% progress bonus. Great Skill Checks cannot be performed while using Autodidact.Autodidact is not active when using a Med Kit to heal.", "descEs": "Empiezas la partida con una penalización de progreso del 5 % en pruebas de habilidad de curar a supervivientes. Por cada prueba de habilidad que superes mientras curas a algún superviviente, consigues un distintivo, hasta un máximo de 25. Por cada distintivo, recibes un 15 % de progreso adicional. No podrás conseguir pruebas de habilidad excelentes mientras usas Autodidacta.Autodidacta no aplica si usas un botiquín para curar.", "es": "Autodidacta", "charEn": "Adam Francis", "charFr": "Adam Francis", "charEs": "Adam Francis"},{"id": "breakdown", "name": "Breakdown", "side": "survivor", "img": "data:image/png;base64,", "desc": "Chaque fois que vous êtes libéré d’un crochet (en vous échappant ou en étant secouru), ce dernier se brise et vous pouvez voir l’aura du tueur pendant 6 secondes. Un crochet brisé par cette compétence met 180 secondes à réapparaître.", "fr": "Effondrement", "descEn": "Any time you are removed from a hook (escaped or saved), the hook breaks and the Killer's aura is shown to you for 6 seconds. A hook broken by this perk takes 180 seconds to respawn.", "descEs": "Cada vez que te liberas de un gancho (por tus medios o con ayuda), el gancho se rompe y se te revela el aura del asesino durante 6 segundos. Un gancho roto con esta habilidad tarda 180 segundos en reaparecer.", "es": "Ruptura", "charEn": "Jeff Johansen", "charFr": "Jeff Johansen", "charEs": "Jeff Johansen"},{"id": "solidarity", "name": "Solidarity", "side": "survivor", "img": "data:image/png;base64,", "desc": "Partager des expériences douloureuses a un pouvoir curatif. Quand vous êtes blessé, soigner un survivant sans trousse de soins vous soigne également à un taux de conversion de 50 %.", "fr": "Solidarité", "descEn": "Sharing painful experiences has the power to heal. While injured, healing a Survivor without using a Med-kit also heals you at a 50% conversion rate.", "descEs": "Compartir experiencias dolorosas tiene el poder de curar. Si te han herido, cuando curas a un superviviente sin usar un botiquín también te curas a ti a un 50 % de la velocidad normal.", "es": "Solidaridad", "charEn": "Jane Romero", "charFr": "Jane Romero", "charEs": "Jane Romero"},{"id": "poised", "name": "Poised", "side": "survivor", "img": "data:image/png;base64,", "desc": "Atteindre des objectifs renforce votre confiance. Quand un générateur est réparé, vous ne laissez aucune marque d'éraflures pendant 10 secondes.", "fr": "Assurance", "descEn": "Achieving goals boosts your confidence. After a generator is completed, you leave no scratch marks for 10 seconds.", "descEs": "Alcanzar objetivos te da confianza. Después de completar un generador, no dejas marcas de arañazos durante 10 segundos.", "es": "Serenidad", "charEn": "Jane Romero", "charFr": "Jane Romero", "charEs": "Jane Romero"},{"id": "flipFlop", "name": "Flip-Flop", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous possédez la capacité improbable d'échapper à l'inévitable. En état critique, 50 % de vos progrès de récupération sont convertis en progrès de gigotement quand le Tueur vous saisit, jusqu'à un maximum de 50 % de progrès de gigotement au total.", "fr": "À la revoyure", "descEn": "You have an uncanny ability to escape the inevitable. While in dying state, 50% of your recovery progression is converted into wiggle progression when you are picked up by The Killer, up to a maximum of 50% total wiggle progression.", "descEs": "Tienes una habilidad asombrosa para escapar de lo inevitable. Cuando estás agonizante, un 50 % de tu progreso de recuperación se convierte en progreso de forcejeo cuando te recoge el asesino, hasta un máximo del 50 % del total.", "es": "Hasta otra", "charEn": "Ashley J. Williams", "charFr": "Ashley J. Williams", "charEs": "Ashley J. Williams"},{"id": "mettleOfMan", "name": "Mettle of Man", "side": "survivor", "img": "data:image/png;base64,", "desc": "Le mal parvient toujours à vous trouver. Force de caractère s’active après avoir effectué Coup de protection 3 fois lors d'un événement à score. Une fois la compétence activée, la prochaine attaque qui devrait vous faire passer d’un état blessé à un état critique est ignorée. La prochaine fois que vous récupérerez 100 % de votre santé, votre aura sera détectée par le tueur si vous êtes à plus de 16 mètres de lui. Force de caractère sera désactivée la prochaine fois que vous serez en état critique. Augmente vos chances de devenir l’obsession du tueur.Le tueur ne peut être obsédé que par un survivant à la fois.", "fr": "Force de caractère", "descEn": "Evil has a way of always finding you. After you earn 3 Protection Hit scoring events, Mettle of Man activates. Once activated, the next occasion that would put you into the dying state from the injured state is ignored. The next time you heal back to full health, your aura will be revealed to the Killer when you are further than 16 meters from the Killer. Mettle of Man will deactivate the next time you are put into the dying state. Increases your chances to be the Killer’s Obsession.The Killer can only be obsessed with one Survivor at a time.", "descEs": "El mal siempre termina encontrándote. El temple del hombre se activa después de recibir 3 golpes por proteger a supervivientes. Una vez activada, serás invulnerable a cualquier daño recibido que te hubiera dejado agonizante cuando estés herido. La próxima vez que recuperes tu salud al completo, tu aura se le revelará al asesino si te encuentras a más de 16 metros de él. El temple del hombre no se desactivará hasta que vuelva a dejarte agonizante. Aumenta tus posibilidades de ser la obsesión del asesino.El asesino no puede obsesionarse con más de un superviviente.", "es": "El temple del hombre", "charEn": "Ashley J. Williams", "charFr": "Ashley J. Williams", "charEs": "Ashley J. Williams"},{"id": "fixated", "name": "Self-Aware", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous connaissez vos faiblesses et vous refusez de vous en cacher. Vous pouvez voir vos propres marques d’éraflures en permanence. Vous marchez 20 % plus vite.", "fr": "Conscience de soi", "descEn": "You know your weaknesses and refuse to hide from them. You can see your own scratch marks at all times. You walk 20% faster.", "descEs": "Conoces tus debilidades y no buscas ocultarte de ellas. Ves tus marcas de arañazos en todo momento. Caminas un 20 % más deprisa.", "es": "Conciencia", "charEn": "Nancy Wheeler", "charFr": "Nancy Wheeler", "charEs": "Nancy Wheeler"},{"id": "survivalInstincts", "name": "Inner Healing", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous vous concentrez sur vous-même et faites confiance à votre instinct quand vous vous sentez seul et perdu. Chaque fois que vous purifiez un totem, Guérison intérieure s’active. Si vous avez déjà l’effet de statut Brisé, Guérison intérieure ne s’active pas. Tant que Guérison intérieure est activée, se cacher dans un casier pendant 20 secondes en étant blessé vous soignera automatiquement. Guérison intérieure se désactive dès cela fait.", "fr": "Guérison intérieure", "descEn": "You look inward and trust your instincts when you feel lost and alone. Each time you cleanse a Totem, Inner Healing activates. If you are already afflicted by the Broken status effect, Inner Healing does not activate. While Inner Healing is active, hiding inside a locker for 20 seconds while injured automatically heals you. Inner Healing deactivates as soon as it has successfully triggered.", "descEs": "Buscas en tu interior y confías en tu instinto siempre que te embarga la desolación y pierdes el rumbo. Cada vez que purificas un tótem, se activa Curación interior. Curación interior no se activa si estás sufriendo el efecto de estado Desesperanza. Mientras Curación interior esté activa, si te escondes en una taquilla durante 20 segundos y sufres una herida, se te curará automáticamente. Curación interior se desactiva inmediatamente después de surtir efecto.", "es": "Curación interior", "charEn": "Nancy Wheeler", "charFr": "Nancy Wheeler", "charEs": "Nancy Wheeler"},{"id": "situationalAwareness", "name": "Situational Awareness", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous êtes conscient de ce qui vous entoure et vous partagez vos informations avec les autres. L’aura du générateur que vous êtes en train de réparer apparaît à tous les autres survivants situés à moins de 32 mètres. Si le tueur met à terre un survivant pendant que vous réparez un générateur, vous voyez l’aura de tous les autres survivants pendant 10 secondes.", "fr": "Conscience situationnelle", "descEn": "You’re aware of your surroundings and share the information with others. The aura of the generator you are currently repairing is revealed to all other Survivors located within 32 meters. If The Killer downs a Survivor while you are repairing a generator, you see the aura of all other Survivors for 10 seconds.", "descEs": "Prestas atención a tu entorno y compartes la información con los demás. El aura del generador que estés reparando se revela a los demás supervivientes que se encuentren en un radio de 32 metros. Si el asesino derriba a un superviviente mientras estás reparando un generador, ves el aura de los demás supervivientes durante 10 segundos.", "es": "Percepción situacional", "charEn": "Nancy Wheeler", "charFr": "Nancy Wheeler", "charEs": "Nancy Wheeler"},{"id": "camaraderie", "name": "Kinship", "side": "survivor", "img": "data:image/png;base64,", "desc": "L’importance de l’amitié vous a rendu plus fort. Camaraderie s’active quand vous êtes sur le crochet pendant la phase de lutte. Si un autre survivant se tient à 8 mètres de vous pendant que Camaraderie est activée, le chronomètre de crochet est mis en pause pendant 4 secondes.", "fr": "Affinités", "descEn": "The importance of friendship has given you strength. Kinship activates when you are in the struggle phase on the hook. If another Survivor is within 8 meters of your hook while Kinship is active, the hook timer is paused for 4 seconds.", "descEs": "La importancia de la amistad te ha dado fuerzas. Mientras estés en la fase de forcejeo en el gancho, se activa Alianza. Si otro superviviente se encuentra dentro de un radio de 8 metros de tu gancho mientras Alianza está activa, el temporizador del gancho se detiene durante 4 segundos.", "es": "Alianza", "charEn": "Steve Harrington", "charFr": "Steve Harrington", "charEs": "Steve Harrington"},{"id": "pushThroughIt", "name": "Renewal", "side": "survivor", "img": "data:image/png;base64,", "desc": "Après avoir soigné l’équivalent d’un état de santé chez les autres survivants, Renouvellement s’active. Si vous êtes déjà sous l’effet de statut Brisé, Renouvellement ne s’active pas. Tant que Renouvellement est activé, votre libération suivante d’un crochet, avec ou sans aide, vous place sous l’effet de statut Brisé. Après une durée totale de 20 secondes, Renouvellement vous soigne automatiquement de blessé à en forme. Renouvellement se désactive dès que vous êtes en forme ou si vous tombez en état critique avant que Renouvellement termine avec succès son activation. Vous perdez l’effet de statut Brisé.", "fr": "Renouvellement", "descEn": "When you have healed other Survivors for the equivalent of one health state, Renewal activates. If you are already afflicted by the Broken status effect, Renewal does not activate. While Renewal is activated, the next time you are unhooked or you unhook yourself, you are affected by the Broken status effect. After a total duration of 20 seconds, Renewal automatically heals you from injured to healthy. Renewal deactivates once you become healthy or if you are put into the dying state before Renewal successfully triggers. You lose the Broken status effect.", "descEs": "Cuando curas a otros supervivientes el equivalente a un estado de salud, se activa Renovación. Renovación no se activa si estás sufriendo el efecto de estado Desesperanza. Mientras Renovación esté activa, la próxima vez que te desenganchen o te desenganches tú por tus propios medios se te aplicará el efecto de estado Desesperanza. Después de 20 segundos en total, Renovación te curará automáticamente de herido a ileso. Renovación se desactivará cuando te hayas recuperado del todo o si te dejan en estado agonizante antes de que Renovación se active. Perderás el efecto de estado Desesperanza.", "es": "Renovación", "charEn": "Steve Harrington", "charFr": "Steve Harrington", "charEs": "Steve Harrington"},{"id": "guardian", "name": "Guardian", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous risquez tout pour aider ceux dans le besoin. Lorsque vous libérez un survivant d’un crochet, il ne laisse pas de marques d’éraflure ni de flaques de sang et bénéficie d’un effet de statut Rapidité de 8 % pendant 7 secondes. Vous voyez l’aura du tueur pendant 8 secondes.", "fr": "Gardien", "descEn": "You risk it all to help those in need. When you unhook a Survivor, they won’t leave scratch marks or pools of blood, and they gain a 8% Haste status effect for 7 seconds. You see the Killer's aura for 8 seconds.", "descEs": "Lo arriesgas todo para ayudar a quienes te necesitan. Cuando descuelgas a un superviviente, este no deja marcas de arañazos ni charcos de sangre y obtiene un 8 % del efecto de estado Celeridad durante 7 segundos. Puedes ver el aura del asesino durante 8 segundos.", "es": "Guardián", "charEn": "Steve Harrington", "charFr": "Steve Harrington", "charEs": "Steve Harrington"},{"id": "breakout", "name": "Breakout", "side": "survivor", "img": "data:image/png;base64,", "desc": "Quand quelqu’un a des problèmes, vous vous donnez à fond et vous poussez les autres à surmonter les obstacles. À 6 mètres maximum d’un survivant transporté, vous bénéficiez de l’effet de statut Rapidité, votre vitesse de mouvement augmente de 7 % et la vitesse de gigotement du survivant transporté augmente de 20 %.", "fr": "Évasion", "descEn": "You kick into high gear when someone’s in trouble, inspiring them to overcome any obstacle. When within 6 meters of a carried Survivor, you gain the Haste status effect, moving at 7% increased speed. The carried Survivor’s wiggle speed is increased by 20%.", "descEs": "Cuando alguien tiene problemas, te vienes arriba y lo animas a superar cualquier obstáculo. Cuando estás a menos de 6 metros de un superviviente con el que esté cargando el asesino, se te aplica afecta el efecto de estado Celeridad, que aumenta un 7 % tu velocidad de movimiento. El superviviente forcejea un 20 % más rápido.", "es": "Fuga", "charEn": "Yui Kimura", "charFr": "Yui Kimura", "charEs": "Yui Kimura"},{"id": "redHerring", "name": "Red Herring", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous avez remarqué que les gens font attention à ce qui fait le plus de bruit. Après avoir réparé un générateur pendant au moins 3 secondes, il sera entouré d’une aura jaune que personne d’autre que vous ne pourra voir. Le générateur reste signalé jusqu’à ce que vous le répariez complètement, que vous répariez un autre générateur, ou que vous entriez dans un casier. Entrer dans un casier déclenche un fort signal sonore du générateur que seul le tueur peut voir. Leurre ne peut être activé qu’une fois toutes les 40 secondes.", "fr": "Leurre", "descEn": "You’ve noticed that people pay attention to whatever makes the loudest noise. After repairing a generator for at least 3 seconds, it will be highlighted to you with a yellow aura. The generator stays highlighted until it is fully repaired, you repair a new generator, or enter a locker. Entering any locker will trigger a loud noise indicator for The Killer at the highlighted generator's location. Red Herring can only be triggered once every 40 seconds.", "descEs": "Has descubierto que la gente siempre presta atención a lo que hace más ruido. Tras reparar un generador durante al menos 3 segundos, se iluminará con un aura amarilla solo visible para ti. El generador permanecerá iluminado hasta que sea reparado por completo, repares otro generador o entres en una taquilla. Entrar en una taquilla activará una notificación de ruido intenso para el asesino en la ubicación del generador iluminado. Bulo solo puede activarse una vez cada 40 segundos.", "es": "Bulo", "charEn": "Zarina Kassir", "charFr": "Zarina Kassir", "charEs": "Zarina Kassir"},{"id": "soulGuard", "name": "Soul Guard", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous avez surmonté d’énormes épreuves, ce qui vous a rendu plus fort. Gagnez l’effet de statut Endurance pendant 8 secondes après avoir reçu des soins ou après avoir récupéré de l’état critique. Quand vous subissez une malédiction à la suite d’un sort, vous pouvez récupérer complètement de l’état critique. Cet effet peut uniquement être déclenché toutes les 30 secondes.", "fr": "Protection de l’âme", "descEn": "You have been through immense hardship and you’re stronger for it. Gain the Endurance status effect for 8 seconds after being healed or having recovered from the dying state. While cursed by a Hex, you can fully recover from the dying state. This effect can only trigger once every 30 seconds.", "descEs": "Superar las enormes penalidades a las que te has tenido que enfrentar te ha hecho más fuerte. Se te aplica el efecto de estado Resistencia durante 8 segundos después de que te curen o de haberte recuperado tras estar agonizante. Mientras te afecte un maleficio, puedes recuperarte por completo del estado agonizante. Este efecto solo se puede activar una vez cada 30 segundos.", "es": "Salvaguarda de alma", "charEn": "Cheryl Mason", "charFr": "Cheryl Mason", "charEs": "Cheryl Mason"},{"id": "bloodPact", "name": "Blood Pact", "side": "survivor", "img": "data:image/png;base64,", "desc": "C’est comme si une part latente de vous-même s’était réveillée. Vous avez la sensation de pouvoir vous dépasser pour porter secours. Lorsque l’obsession ou vous-même êtes blessés, vous voyez vos auras respectives. Après avoir terminé une action de soin sur l’obsession, ou quand celle-ci termine une action de soin sur vous, vous gagnez tous les deux un effet de statut Rapidité de % jusqu'à ce que vous soyez à plus de 16 mètres l'un de l'autre. Réduit les probabilités de devenir l’obsession. Si vous êtes l’obsession, cette compétence se désactive.", "fr": "Pacte de sang", "descEn": "It’s as if a latent part of yourself has awakened. You feel like you can reach out beyond yourself for assistance. When you or the Obsession are injured, you both see each other's auras. After completing a healing action on the Obsession, or having the Obsession complete a healing action on you, you both gain a % Haste status effect until no longer within 16 meters of each other. Reduces the odds of being the Obsession. If you are the Obsession, this perk deactivates.", "descEs": "Es como si una parte latente de ti hubiera despertado. Sientes que puedes buscar ayuda más allá de tu propio ser. Cuando la obsesión o tú estáis heridos, ella ve tu aura y tú la suya. Después de completar una acción de curación sobre la obsesión o de que ella complete una acción de curación sobre ti, se os aplica a ambos un % del efecto de estado Celeridad hasta que estéis a más de 16 metros el uno del otro. Reduce las posibilidades de ser la obsesión. Si eres la obsesión, esta habilidad se desactiva.", "es": "Pacto de sangre", "charEn": "Cheryl Mason", "charFr": "Cheryl Mason", "charEs": "Cheryl Mason"},{"id": "repressedAlliance", "name": "Repressed Alliance", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous avez l'habitude que des forces maléfiques vous poursuivent et vous avez commencé à l’utiliser à votre avantage. Alliance refoulée s’active après avoir réparé des générateurs pendant un total de 45 secondes. Quand vous réparez un générateur avec la compétence active, appuyez sur le bouton de capacité active pour faire appel à l’Entité afin de bloquer le générateur pendant 30 secondes. La compétence se désactive. Les générateurs affectés sont indiqués par une aura blanche à tous les survivants.", "fr": "Alliance refoulée", "descEn": "You’re accustomed to being hunted by malicious forces, and you’ve begun using it to your advantage. Repressed Alliance activates after repairing generators for a total of 45 seconds. When repairing a generator while the perk is active, press the Active Ability button to call upon The Entity to block the generator for 30 seconds. The perk deactivates. Affected generators will be revealed by a white aura to all Survivors.", "descEs": "Te has acostumbrado a que te persigan las fuerzas malignas y has empezado a usarlo a tu favor. Supresión de alianza se activa tras reparar generadores durante un total de 45 segundos. Al reparar un generador mientras la habilidad está activa, pulsa el botón de la habilidad activa para invocar al Ente y bloquear el generador durante 30 segundos. La habilidad se desactiva. Los generadores afectados brillarán con un aura blanca que se mostrará a todos los supervivientes.", "es": "Supresión de alianza", "charEn": "Cheryl Mason", "charFr": "Cheryl Mason", "charEs": "Cheryl Mason"},{"id": "visionary", "name": "Visionary", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous êtes incroyablement concentré sur les moyens de vous enfuir. Vous voyez l’aura des générateurs dans un rayon de 32 mètres. Quand un générateur est réparé, Visionnaire est désactivé pendant 16 secondes.", "fr": "Visionnaire", "descEn": "You’re remarkably focused on your means of escape. You see generator’s auras within 32 meters. Anytime a generator is completed, Visionary is disabled for 16 seconds.", "descEs": "Tienes una facilidad innata para encontrar formas de escapar. Ves las auras de los generadores a una distancia máxima de 32 metros. Visión de futuro se desactiva durante 16 segundos cada vez que se completa un generador.", "es": "Visión de futuro", "charEn": "Felix Richter", "charFr": "Felix Richter", "charEs": "Felix Richter"},{"id": "desperateMeasures", "name": "Desperate Measures", "side": "survivor", "img": "data:image/png;base64,", "desc": "Même dans vos pires moments, vous refusez d’échouer. Pour chaque survivant blessé, suspendu à un crochet ou en état critique, la vitesse de vos soins et de vos décrochages augmente de 14 %.", "fr": "Mesures désespérées", "descEn": "You refuse to fail, even during your darkest hour. For each injured, hooked, or dying Survivor, increase the speed of your healing and unhook actions by 14%.", "descEs": "Te niegas a fracasar incluso en tus peores momentos. Por cada superviviente herido, enganchado o agonizante, la velocidad de tus acciones de curación y desenganche aumenta un 14 %.", "es": "Medidas desesperadas", "charEn": "Felix Richter", "charFr": "Felix Richter", "charEs": "Felix Richter"},{"id": "builtToLast", "name": "Built to Last", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous savez comment tirer le meilleur de vos outils. Après s’être caché dans un casier pendant 50 secondes avec un objet déchargé en main, il récupèrera 99 % de ses charges. Chaque utilisation de Conçu pour durer réduit de -33 % la quantité de charges récupérées.", "fr": "Conçu pour durer", "descEn": "You know how to get the most out of your tools. After hiding inside a locker for 50 seconds with a depleted item in hand, 99% of its charges are refilled. Each use of Built to Last reduces the amounts of charges refilled by -33%.", "descEs": "Sabes cómo sacarles partido a tus herramientas. Tras ocultarte en una taquilla durante 50 segundos con un objeto desgastado en tu posesión, se rellenará un 99 % de las cargas. Cada vez que se use Construcción duradera, se reducen las cargas repuestas un -33 %.", "es": "Construcción duradera", "charEn": "Felix Richter", "charFr": "Felix Richter", "charEs": "Felix Richter"},{"id": "appraisal", "name": "Appraisal", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous avez l’œil pour remarquer ce que beaucoup négligent. Commencez la partie avec 3 jetons. Quand un coffre a déjà été ouvert, consommez un jeton pour le fouiller à la recherche d’un objet. Vous ne pouvez le faire qu’une seule fois par coffre. Votre fouille des coffres est 80 % plus rapide.", "fr": "Estimation", "descEn": "You have a careful eye that notices what many overlook. Start the trial with 3 tokens. When a chest has already been opened, consume a token to rummage through it for an item. Rummaging can only be performed once per chest. You rummage through chests 80% faster.", "descEs": "Posees una capacidad de observación superior a la media. Comienzas la partida con 3 distintivos. Si ya se ha abierto un cofre, puedes gastar un distintivo para buscar un objeto en él. Solo puedes rebuscar una vez por cofre. La velocidad a la que rebuscas en los cofres aumenta un 80 %.", "es": "Evaluación", "charEn": "Élodie Rakoto", "charFr": "Élodie Rakoto", "charEs": "Élodie Rakoto"},{"id": "deception", "name": "Deception", "side": "survivor", "img": "data:image/png;base64,", "desc": "Votre style de vie aventureux vous pousse à donner de mauvaises indications. Interagir avec un casier tout en sprintant déclenchera une notification sonore à votre position et vous permettra de ne pas laisser de marques d’éraflures pendant 3 secondes. Vous ne pouvez plus entrer dans les casiers lorsque vous sprintez et tant que cette compétence est active. Supercherie peut uniquement être déclenché une fois toutes les 40 secondes.", "fr": "Supercherie", "descEn": "Your adventurous lifestyle requires moments of crafty misdirection. Interacting with a locker while sprinting will trigger a loud noise notification at your location and cause you to leave no scratch marks for 3 seconds. You no longer enter lockers while sprinting and while this perk is active. Deception can only be triggered once every 40 seconds.", "descEs": "Tu estilo de vida aventurero trae consigo momentos donde deberás sacar tu lado más astuto. Si interactúas con una taquilla al esprintar, se activará una notificación de ruido intenso en tu ubicación y no dejarás marcas de arañazos durante los próximos 3 segundos. Ya no podrás entrar en las taquillas al esprintar y mientras la habilidad esté activa. Engaño solo puede activarse una vez cada 40 segundos.", "es": "Engaño", "charEn": "Élodie Rakoto", "charFr": "Élodie Rakoto", "charEs": "Élodie Rakoto"},{"id": "powerStruggle", "name": "Power Struggle", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous n’avez jamais abandonné et vous ne comptez pas commencer aujourd’hui. Quand vous êtes en état critique, vous voyez l’aura des palettes disponibles. Quand le tueur vous transporte, débattez-vous jusqu’à 35 % de la barre de progression pour activer Bras de fer. Tant que Bras de fer est activé, vous pouvez faire tomber une palette debout à proximité pour étourdir le tueur.", "fr": "Bras de fer", "descEn": "You’ve never given up and you’re not about to start now. Whenever you are in the dying state, you see the auras of available Pallets. While being carried by The Killer, reaching 35% wiggle progress activates Power Struggle. While Power Struggle is active, you can drop a nearby, standing pallet to stun The Killer.", "descEs": "Nunca te has rendido, así que tampoco vas a hacerlo ahora. Cuando sufras un estado agonizante, verás las auras de los palés disponibles. Cuando un asesino te lleva, forcejea hasta alcanzar un 35 % para activar Lucha intensa. Cuando Lucha intensa esté activa, podrás soltar un palé fijo cercano para aturdir a un asesino.", "es": "Lucha intensa", "charEn": "Élodie Rakoto", "charFr": "Élodie Rakoto", "charEs": "Élodie Rakoto"},{"id": "fastTrack", "name": "Fast Track", "side": "survivor", "img": "data:image/png;base64,", "desc": "Parfois, pour passer en tête, il faut sacrifier les autres. Chaque fois qu’un survivant est suspendu à un crochet, vous gagnez 3 jetons.Vous consommez tous vos jetons après un excellent test d’habileté sur un générateur. Chaque jeton consommé accorde 27 % de progression bonus pour les tests d’habileté excellents lors de la réparation de générateurs.", "fr": "Voie rapide", "descEn": "Sometimes the sacrifice of others is necessary to get ahead. Whenever another Survivor is hooked, you gain 3 tokens. You consume all tokens after a great Skill Check on a generator. Each token consumed grants a 27% bonus progression for great Skill Checks when repairing generators.", "descEs": "A veces, es necesario que otros se sacrifiquen por tu propio bien. Cada vez que se cuelgue a otro superviviente, obtienes 3 distintivos. Consumes todos los distintivos tras una prueba de habilidad excelente en un generador. Cada distintivo consumido obtiene una progresión adicional del 27 % con las pruebas de habilidad excelentes al reparar generadores.", "es": "Primera línea", "charEn": "Yun-Jin Lee", "charFr": "Yun-Jin Lee", "charEs": "Yun-Jin Lee"},{"id": "smashHit", "name": "Smash Hit", "side": "survivor", "img": "data:image/png;base64,", "desc": "Quand votre rival fait une erreur, vous saisissez votre chance. Après avoir étourdi le tueur avec une palette, sprintez à 150 % de votre vitesse normale pendant 4 secondes. Provoque l’effet de statut Épuisement pendant 40 secondes. Cette compétence ne peut être utilisée pendant Épuisement.", "fr": "Succès écrasant", "descEn": "When your rival makes a mistake, you seize the opportunity. After stunning the Killer with a pallet, break into a sprint at 150% your normal running speed for 4 seconds. Causes the Exhausted status effect for 40 seconds. This perk cannot be used while Exhausted.", "descEs": "Cuando tu rival comete un error, tienes que aprovechar la oportunidad. Tras aturdir al asesino con un palé, esprinta con un 150 % de tu habilidad normal cuando corres durante 4 segundos. Provoca el efecto de estado Agotamiento durante 40 segundos. Esta habilidad no se puede usar con Agotamiento.", "es": "Éxito aplastante", "charEn": "Yun-Jin Lee", "charFr": "Yun-Jin Lee", "charEs": "Yun-Jin Lee"},{"id": "self-Preservation", "name": "Self-Preservation", "side": "survivor", "img": "data:image/png;base64,", "desc": "La vie ne pardonne rien. Parfois, il vaut mieux se préoccuper de soi-même. Chaque fois qu’un autre survivant à 16 mètres de vous est frappé par une attaque de base ou une attaque spéciale, Instinct de survie s’active. Vos marques d’éraflures, vos flaques de sang et vos gémissements de douleur sont dissimulés pendant 10 secondes.", "fr": "Instinct de survie", "descEn": "Life's unforgiving. Sometimes it's best to look out for yourself. Whenever another Survivor within 16 meters of you gets hit by a basic attack or a special attack, Self-Preservation activates. Your scratch marks, pools of blood and grunts of pain are hidden for 10 seconds.", "descEs": "La vida es cruel y es mejor no depender de nadie. Cuando otro superviviente sufra un ataque básico o especial a 16 metros de ti, se activará Autoconservación. Tus marcas de arañazos, charcos de sangre y gruñidos de dolor se ocultan durante 10 segundos.", "es": "Autoconservación", "charEn": "Yun-Jin Lee", "charFr": "Yun-Jin Lee", "charEs": "Yun-Jin Lee"},{"id": "counterforce", "name": "Counterforce", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous savez comment faire face à un ennemi plus fort que vous, et cela commence en pourchassant et en éliminant son soutien. Vous purifiez les totems 20 % plus vite. Après avoir purifié un totem, vous voyez l’aura du totem le plus éloigné de vous pendant 4 secondes et vous gagnez un bonus de vitesse cumulable supplémentaire de 20 % pour purifier des totems tout le reste de la partie. « Je ne suis pas contre un peu de travail de détective. » — Jill Valentine", "fr": "Contre-force", "descEn": "You know how to withstand an enemy stronger than you, and it starts with hunting down and knocking out their support. You cleanse Totems 20% faster. After cleansing a Totem, you see the aura of the furthest Totem from you for 4 seconds and you gain an additional 20% stackable speed bonus to cleansing Totems for the remainder of the trial. \"I don't mind a little detective work.\" —Jill Valentine", "descEs": "Sabes resistir ante un enemigo más fuerte que tú: lo principal es dar caza y acabar con sus refuerzos. Purifica tótems un 20 % más rápido. Tras purificar un tótem, ves el aura del tótem más lejano a ti durante 4 segundos y obtienes un 20 % de velocidad adicional acumulable para purificar tótems para el resto de la partida. \"No me desagrada hacer un poco de detective\". (Jill Valentine)", "es": "Contrafuerza", "charEn": "Jill Valentine", "charFr": "Jill Valentine", "charEs": "Jill Valentine"},{"id": "resurgence", "name": "Resurgence", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous avez survécu à des situations quasi impossibles... et vous recommencerez. Obtenez une progression de soins de 50 % immédiatement après avoir été libéré d’un crochet ou vous être libéré vous-même. « C’est mon tour, saloperie. » — Jill Valentine", "fr": "Renaissance", "descEn": "You've come back from near impossible odds... and you'll do it again. Gain 50% healing progress instantly after being unhooked or unhooking yourself. \"It's my turn, bitch.\" —Jill Valentine", "descEs": "Has sobrevivido a algo que parecía imposible... y volverás a hacerlo. Obtienes un 50 % de velocidad de curación al instante después de que alguien te desenganche o de que te desenganches por tus propios medios. \"Ahora es mi turno, bicho asqueroso\". (Jill Valentine)", "es": "Resurgimiento", "charEn": "Jill Valentine", "charFr": "Jill Valentine", "charEs": "Jill Valentine"},{"id": "blastMine", "name": "Blast Mine", "side": "survivor", "img": "data:image/png;base64,", "desc": "Lorsque le combat direct n’est pas une option, vous trouvez toujours un moyen de contre-attaquer. Mine explosive s’active après avoir terminé un total de 66 % de progression de réparation des générateurs. Après avoir réparé un générateur pendant au moins 3 secondes, appuyez sur le bouton de capacité pour installer un piège qui reste actif pendant 45 secondes. L’aura des générateurs affectés est révélée en jaune à tous les survivants. Un seul piège peut être actif sur un générateur. Lorsque le tueur frappe un générateur piégé, le piège explose, étourdissant et aveuglant quiconque se trouve à proximité. Mine explosive est alors désactivée. « Tu veux les S.T.A.R.S. ? Je vais te faire goûter aux S.T.A.R.S. ! » - Jill Valentine", "fr": "Mine explosive", "descEn": "When direct combat isn't an option, you still find ways to strike back. Blast Mine activates after completing a total of 66% worth of repair progress on generators. After repairing a generator for at least 3 seconds, press the Ability button to install a trap which stays active for 45 seconds. Affected generators will be revealed to all Survivors by a yellow aura. Only one trap can be active on a generator. When the Killer damages a trapped generator, the trap explodes, stunning them and blinding anyone nearby. Blast Mine is then deactivated. \"You want S.T.A.R.S.? I'll give you S.T.A.R.S.! \" —Jill Valentine", "descEs": "Cuando el combate cuerpo a cuerpo no es una opción, siempre se te ocurre alguna alternativa. Mina explosiva se activa tras completar un total de 66 % como progreso de reparación de generadores. Después de reparar un generador durante un mínimo de 3 segundos, pulsa el botón de la habilidad para instalar una trampa que permanezca activa durante 45 segundos. Los generadores afectados se mostrarán a los supervivientes con un aura amarilla. Solo se puede activar una trampa en un generador. Cuando el asesino patea un generador con trampa, esta explota, aturdiendo y cegando a quienes estén cerca. A continuación, Mina explosiva se desactivará. \"¡Ahora sí que vas a ver las estrellas!\". (Jill Valentine)", "es": "Mina explosiva", "charEn": "Jill Valentine", "charFr": "Jill Valentine", "charEs": "Jill Valentine"},{"id": "biteTheBullet", "name": "Bite the Bullet", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous souffrez autant que n’importe qui, mais vous préférez que les autres ne le sachent pas. Pendant les soins, ni vous, ni le survivant que vous soignez ne faites de bruit, pas même de grognements de douleur. Il n’y a pas de notification sonore lors de tests d’habileté de soins ratés et la guérison recule uniquement de 1 %. « Je peux le faire. » — Leon S. Kennedy", "fr": "Serrer les dents", "descEn": "Pain hurts you as much as anyone, but you'd prefer others don't know that. When healing, you and the Survivor you're healing make no noise, including grunts of pain. There is no noise notification on failed healing Skill Checks and healing regresses by only 1%. \"I can do this.\" —Leon S. Kennedy", "descEs": "Sientes el dolor igual que el resto, pero no quieres que nadie se entere. Ni el superviviente al que estés curando ni tú emitís ningún sonido, ni un gruñido. No hay notificación de ruido en las pruebas de habilidad de curación fallidas y la curación se revierte solo un 1 %. \"Puedo hacerlo\". (Leon S. Kennedy)", "es": "De tripas corazón", "charEn": "Leon S. Kennedy", "charFr": "Leon S. Kennedy", "charEs": "Leon S. Kennedy"},{"id": "rookieSpirit", "name": "Rookie Spirit", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous ne perdez pas de vue vos objectifs quand ils vous glissent entre les doigts. Terminez 3 tests d’habileté bons ou excellents en réparant des générateurs pour activer Détermination du bleu pour le reste de la partie. Une fois actif, vous pouvez voir l’aura des générateurs en régression. « J’y mettrai fin, lieutenant. Je le promets. » — Leon S. Kennedy", "fr": "Détermination du bleu", "descEn": "You keep a careful eye on objectives when they're slipping away. Complete 3 good or great Skill Checks while repairing generators to activate Rookie Spirit for the remainder of the trial. Once active, you can see the aura of regressing generators. \"I'll stop this, lieutenant. I promise.\" —Leon S. Kennedy", "descEs": "Prestas mucha atención a los objetivos cuando se escapan. Completa 3 pruebas de habilidad superadas o excelentes mientras reparas generadores para activar Espíritu de novato para el resto de la partida. Cuando se active, podrás ver el aura de los generadores revertidos. \"Pondré fin a esto, teniente. Se lo prometo\". (Leon S. Kennedy)", "es": "Espíritu de novato", "charEn": "Leon S. Kennedy", "charFr": "Leon S. Kennedy", "charEs": "Leon S. Kennedy"},{"id": "clairvoyance", "name": "Clairvoyance", "side": "survivor", "img": "data:image/png;base64,", "desc": "Une énergie intrinsèque qui voit au-delà de votre vision. Clairvoyance s’active chaque fois que vous purifiez un totem. Quand vos mains sont vides, maintenez le bouton Capacité pour débloquer tout votre potentiel de détection d’aura. Pendant 10 secondes, vous voyez les auras des interrupteurs des portes de sortie, des générateurs, des crochets, des coffres et de la trappe dans un rayon de 64 mètres.", "fr": "Clairvoyance", "descEn": "There is an intrinsic energy in you that sees beyond your vision. Clairvoyance activates whenever you cleanse a Totem. When empty-handed, hold the Ability button to unlock your full aura-reading potential. For up to 10 seconds, you see the auras of exit gate switches, generators, hooks, chests and the Hatch within a 64 meter range.", "descEs": "Hay una energía intrínseca en tu interior que percibe más allá de tu visión. Clarividencia se activa cuando purificas un tótem. Cuando tengas las manos vacías, mantén pulsado el botón de la habilidad para desatar todo tu potencial para percibir auras. Durante un máximo de 10 segundos, podrás ver las auras de los interruptores de las puertas de salida, los generadores, los ganchos, los cofres y la trampilla a una distancia de 64 metros.", "es": "Clarividencia", "charEn": "Mikaela Reid", "charFr": "Mikaela Reid", "charEs": "Mikaela Reid"},{"id": "t_iconPerks_Overcome", "name": "Overcome", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous avez calculé l’énergie que vous pouvez vous risquer à dépenser. Quand vous subissez une blessure, vous conservez le bonus de vitesse de mouvement pendant 2 secondes supplémentaires. Surmonter inflige l'effet de statut Épuisement pendant 40 secondes Surmonter ne peut être utilisé quand Épuisement est actif.", "fr": "Surmonter", "descEn": "You've calculated how much energy you can risk to expend. When you are injured, you retain the movement speed bonus for 2 seconds longer. Overcome causes the Exhausted status effect for 40 seconds. Overcome cannot be used when Exhausted.", "descEs": "Has calculado cuánta energía puedes arriesgarte a emplear. Cuando sufres heridas, mantienes la bonificación de velocidad de movimiento 2 segundos más. Sobreponerse provoca el efecto de estado Agotamiento durante 40 segundos. Sobreponerse no se puede usar cuando sufra Agotamiento.", "es": "Sobreponerse", "charEn": "Jonah Vasquez", "charFr": "Jonah Vasquez", "charEs": "Jonah Vasquez"},{"id": "t_iconPerks_CorrectiveAction", "name": "Corrective Action", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous analysez rapidement les problèmes et corrigez le travail des autres quand ils commettent des erreurs. Vous commencez la partie avec 3 jeton(s) et vous gagnez un jeton (jusqu’à 5 au maximum), pour chaque test d’habileté excellent. Quand un survivant rate un test d’habileté normal alors qu'il coopère avec vous, 1 jeton est consumé et son test d’habileté échoué devient un bon test d’habileté.", "fr": "Mesure de correction", "descEn": "You quickly analyze problems and correct other's work when they make a mistake. You start the trial with 3 token(s) and gain a token, up to a maximum of 5, for every great Skill Check. When a Survivor fails a Normal Skill Check while cooperating with you, 1 token is consumed and their failed Skill Check becomes a good Skill Check.", "descEs": "Analizas los problemas rápido y corriges el trabajo de los demás cuando cometen un error. Empiezas la partida con 3 distintivo(s) y obtienes uno por cada prueba de habilidad excelente hasta un máximo de 5. Cuando un superviviente falla una prueba de habilidad normal mientras coopera contigo, se consume 1 distintivo y su prueba de habilidad fallida se vuelve una prueba de habilidad superada.", "es": "Medida correctiva", "charEn": "Jonah Vasquez", "charFr": "Jonah Vasquez", "charEs": "Jonah Vasquez"},{"id": "t_iconPerks_BoonExponential", "name": "Boon: Exponential", "side": "survivor", "img": "data:image/png;base64,", "desc": "Quand c’est votre tour, vous trouvez le moyen de recalculer les probabilités. Appuyez et maintenez le bouton Capacité près d’un totem passif ou ensorcelé pour le bénir et créer un totem de bénédiction. De doux tintements résonnent dans un rayon de 24 mètre(s). Tout survivant à portée du totem de bénédiction récupère 100 % plus vite et peut récupérer pleinement d’un état critique. Vous ne pouvez bénir qu’un totem à la fois. Toutes les compétences de bénédiction équipées sont actives sur votre totem de bénédiction.", "fr": "Bénédiction : Exponentiel", "descEn": "When it seems like your number is up, you consider ways to recalculate the odds. Press and hold the Ability button near a Dull or Hex Totem to bless it and create a Boon Totem. Soft chimes ring out in a 24 meter range. All Survivors within the Boon Totem's range recover 100% faster and can completely recover from the dying state. You can only bless one Totem at a time. All equipped boon perks are active on your Boon Totem.", "descEs": "Cuando parece que ha llegado tu hora, buscas formas de aumentar tus posibilidades. Mantén pulsado el botón de la habilidad cerca de un tótem de maleficio o apagado para bendecirlo y crear un tótem benefactor. Se escucha la melodía del carillón a una distancia de 24 metros. Todos los supervivientes en el rango de alcance del tótem benefactor se recuperan un 100 % más rápido y se curan por completo del estado agonizante. Solo puedes bendecir un tótem a la vez. Todas las habilidades de bendición estarán activas en el tótem benefactor.", "es": "Bendición: Exponencial", "charEn": "Jonah Vasquez", "charFr": "Jonah Vasquez", "charEs": "Jonah Vasquez"},{"id": "parentalGuidance", "name": "Parental Guidance", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous avez hérité la capacité d'entendre les morts - et maintenant les morts vous avertissent d'un danger. Après avoir étourdi le tueur par n'importe quel moyen, vos marques d'éraflures, vos flaques de sang et vos gémissements de douleur sont dissimulés pendant 7 secondes.", "fr": "Conseils parentaux", "descEn": "You have inherited the ability to hear the dead – and now, the dead warn you of danger. After stunning the Killer by any means, your scratch marks, pools of blood and grunts of pain are hidden for 7 seconds.", "descEs": "Has heredado el don de escuchar a los muertos, y ahora los muertos te advierten del peligro. Tras aturdir al asesino del modo que sea, tus marcas de arañazos, charcos de sangre y gruñidos de dolor se camuflarán durante 7 segundos.", "es": "Consejo paterno", "charEn": "Yoichi Asakawa", "charFr": "Yoichi Asakawa", "charEs": "Yoichi Asakawa"},{"id": "empathicConnection", "name": "Empathic Connection", "side": "survivor", "img": "data:image/png;base64,", "desc": "Votre présence se projette psychiquement sur ceux qui sont en danger. Dès qu'un survivant est blessé, il peut voir votre aura dans un rayon de 96 mètres. Vous pouvez soigner les autres survivants 10 % plus vite.", "fr": "Connexion empathique", "descEn": "Your presence psychically projects itself to those in danger. Whenever another Survivor is injured, they can see your aura within a range of 96 meters. You heal other Survivors 10% faster.", "descEs": "Tu presencia se proyecta psíquicamente hacia quienes están en peligro. Cada vez que otro superviviente está herido, podrá ver tu aura a una distancia de 96 metros. Curas a otros supervivientes un 10 % más rápido.", "es": "Conexión empática", "charEn": "Yoichi Asakawa", "charFr": "Yoichi Asakawa", "charEs": "Yoichi Asakawa"},{"id": "darkTheory", "name": "Boon: Dark Theory", "side": "survivor", "img": "data:image/png;base64,", "desc": "Votre étude obsessive du paranormal vous a donné des connaissances inégalées d'autres royaumes et plans d'existence. Maintenez enfoncé le bouton de capacité près d'un totem passif ou d'un totem ensorcelé pour le bénir et créer un totem de bénédiction. Un doux carillon tinte dans un rayon de 24 mètres. Tout survivant dans le rayon du totem de bénédiction gagne un effet de statut de rapidité de 2 %. Cet effet perdure 4 secondes après avoir quitté le rayon d'action du totem de bénédiction. Vous ne pouvez bénir qu'un seul totem à la fois. Toutes les compétences de bénédiction équipées sont actives sur votre totem de bénédiction.", "fr": "Bénédiction : Théorie ténébreuse", "descEn": "Your obsessive study of the paranormal has given you unprecedented knowledge of other realms and planes of existence. Press and hold the Ability button near a Dull or Hex Totem to bless it and create a Boon Totem. Soft chimes ring out in a 24 meter range. Any Survivors within the Boon Totem’s range gain a 2% Haste status effect. This effect lingers for 4 seconds after leaving the Boon Totem's range. You can only bless one Totem at a time. All equipped boon perks are active on your Boon Totem.", "descEs": "Tu concienzudo estudio de lo paranormal te confiere un conocimiento único de otros reinos y planos existenciales. Mantén pulsado el botón de la habilidad cerca de un tótem de maleficio o apagado para bendecirlo y crear un tótem benefactor. Se escucha la melodía del carillón a una distancia de 24 metros. Todos los supervivientes en el rango de alcance del tótem benefactor obtienen un 2 % del efecto de estado Celeridad. Este efecto dura 4 segundos tras alejarse del tótem benefactor. Solo puedes bendecir un tótem cada vez. Todas las habilidades de bendición estarán activas en el tótem benefactor.", "es": "Bendición: Teoría oscura", "charEn": "Yoichi Asakawa", "charFr": "Yoichi Asakawa", "charEs": "Yoichi Asakawa"},{"id": "innerFocus", "name": "Inner Focus", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vous avez affûté votre capacité à percer le voile du Ravage. Vous pouvez voir les marques d'éraflures des autres survivants. Quand un autre survivant perd un état de santé à mètres de vous, l'aura du tueur vous est révélée pendant 32 secondes.", "fr": "Concentration intérieure", "descEn": "You have honed your ability to see through the haze of the Ravage. You can see other Survivors' scratch marks. Whenever another Survivor loses a health state within meters of you, the Killer's aura is revealed to you for 32 seconds.", "descEs": "Has perfeccionado tu capacidad de ver en la neblina de la Devastación. Puedes ver las marcas de arañazos de otros supervivientes. Si otro superviviente pierde un estado de salud a metros de distancia de ti, se te mostrará el aura del asesino durante 32 segundos.", "es": "Concentración interna", "charEn": "Haddie Kaur", "charFr": "Haddie Kaur", "charEs": "Haddie Kaur"},{"id": "residualManifest", "name": "Residual Manifest", "side": "survivor", "img": "data:image/png;base64,", "desc": "Une vie entière passée à chasser les ténèbres vous a appris que le meilleur désinfectant, c'est la lumière. Après avoir réussi à aveugler le tueur, le tueur subit l'effet de statut Aveuglement pendant 30 secondes. Cette compétence donne la faculté de fouiller un coffre ouvert une fois par partie et garantit d'y trouver une lampe de poche de base.", "fr": "Manifeste résiduel", "descEn": "A lifetime of chasing the darkness has taught you that the best disinfectant is light. After a successful Killer Blind action, the Killer is affected by the Blindness status effect for 30 seconds. This perk grants the ability to rummage through an opened chest once per trial and will guarantee a basic Flashlight.", "descEs": "Toda una vida persiguiendo la oscuridad te ha enseñado que el mejor desinfectante es la luz. Si consigues aplicar Ceguera al asesino, este sufrirá el efecto de estado Ceguera durante 30 segundos. Esta habilidad te permite inspeccionar un cofre abierto en cada partida y recibirás una linterna básica.", "es": "Manifestación residual", "charEn": "Haddie Kaur", "charFr": "Haddie Kaur", "charEs": "Haddie Kaur"},{"id": "overzealous", "name": "Overzealous", "side": "survivor", "img": "data:image/png;base64,", "desc": "Riposter contre le Ravage vous motive et vous inspire. Après avoir purifié n'importe quel totem, cette compétence s'active. Votre vitesse de réparation de générateur augmente de 6 %. Ce bonus est doublé si vous purifiez un totem ensorcelé. Cette compétence se désactive quand vous perdez un état de santé par n'importe quel moyen.", "fr": "Excès de zèle", "descEn": "Fighting back against the Ravage motivates and inspires you. After cleansing any Totem, this perk activates. Your generator repair speed is increased by 6%. This bonus is doubled if you cleanse a Hex totem. This perk deactivates when you lose a health state by any means.", "descEs": "Plantarle cara a la Devastación te motiva y te inspira. Esta habilidad se activa tras purificar un tótem. Tu velocidad de reparación de generadores aumenta un 6 %. Esta bonificación se duplica si purificas un tótem de maleficio. Esta habilidad se desactiva cuando pierdas un estado de salud del modo que sea.", "es": "Pasión", "charEn": "Haddie Kaur", "charFr": "Haddie Kaur", "charEs": "Haddie Kaur"},{"id": "thrillOfTheHunt", "name": "Hex: Thrill of the Hunt", "side": "killer", "img": "data:image/png;base64,", "desc": "Un sort qui puise sa force dans l’espoir. Les faux espoirs des survivants vous excitent et renforcent vos totems. Vous gagnez un jeton pour chaque totem ensorcelé ou passif restant sur la carte. Gagnez 10 % de points de sang en plus par jeton pour les actions de la catégorie Chasseur.La vitesse de purification et de bénédiction de totem des survivants est réduite de 10 % pour chaque jeton. L’effet du sort persiste aussi longtemps que le totem ensorcelé correspondant est debout.", "fr": "Sort : Euphorie de la chasse", "descEn": "A Hex rooting its power on hope. The false hope of Survivors fills you with excitement and strengthens your Totems. For each Dull and Hex Totem remaining on the map gain a token. Gain 10% more Bloodpoints for actions in the Hunter category for each token.Survivors' cleansing and blessing speed is reduced by 10% for each token. The Hex effects persist as long as the related Hex Totem is standing.", "descEs": "Un maleficio que basa su poder en la esperanza. La falsa esperanza de los supervivientes te estimula y fortalece tus tótems. Consigues un distintivo por cada tótem apagado o de maleficio que quede en el mapa. Cada distintivo te proporciona un 10 % más de puntos de sangre por acciones de la categoría Caza.La velocidad de purificación y bendición de los supervivientes se reduce un 10 % por cada distintivo. Los efectos del maleficio perduran mientras su tótem de maleficio correspondiente siga en pie.", "es": "Maleficio: La emoción de la caza", "charEn": "", "charFr": "", "charEs": ""},{"id": "boonDestroyer", "name": "Shattered Hope", "side": "killer", "img": "data:image/png;base64,", "desc": "Pour capturer votre proie, vous devez d'abord anéantir son espoir. Chaque fois que vous éteignez un totem de bénédiction, le totem est détruit à la place. Lorsque vous détruisez ainsi un totem de bénédiction, l'aura de tous les survivants dans le rayon du totem de bénédiction vous est révélée pendant 8 secondes.", "fr": "Espoir brisé", "descEn": "To capture your prey, you must first extinguish their hope. Whenever you snuff a Boon Totem, the totem is destroyed instead. When you destroy a Boon Totem this way, the auras of all Survivors inside the Boon Totem range are revealed to you for 8 seconds.", "descEs": "Para capturar a tu presa, primero debes anular sus esperanzas. Cada vez que apagas un tótem benefactor, el tótem quedará destruido. Si destruyes así un tótem benefactor, se mostrarán las auras de todos los supervivientes en el rango de alcance del tótem benefactor durante 8 segundos.", "es": "Esperanza destruida", "charEn": "", "charFr": "", "charEs": ""},{"id": "playWithYourFood", "name": "Play with your food", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous devenez obsédé par un survivant. Chaque fois que vous chassez la cible de votre obsession et que vous la laissez s’échapper, vous recevez un jeton jusqu’à un maximum de 3 jetons. Chaque jeton augmente votre vitesse de mouvement de 5 %. Effectuer une attaque de base ou une attaque spéciale consomme un jeton. Le tueur ne peut être obsédé que par un survivant à la fois.", "fr": "Jouer avec la nourriture", "descEn": "You become obsessed with one Survivor. Every time you chase your Obsession and let them escape, you receive a token up to a maximum of 3 tokens. Each token increases your movement speed by 5%. Performing a basic attack or Special Attack spends one token. \"The Killer can only be obsessed with one Survivor at a time.", "descEs": "Te obsesionas con un superviviente. Cada vez que persigues a tu obsesión y la dejas escapar, ganas un distintivo, hasta un máximo de 3. Por cada uno que tengas, tu velocidad de movimiento aumenta un 5 %. Cada ataque básico o especial consume un distintivo. El asesino solo se puede obsesionar con un superviviente a la vez.", "es": "Jugar con la comida", "charEn": "The Shape", "charFr": "La Silhouette", "charEs": "La Forma"},{"id": "dyingLight", "name": "Dying Light", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous devenez obsédé par un survivant. Votre obsession bénéficie d’un bonus de 33 % à la vitesse d’action pour décrocher et soigner d’autres survivants. Chaque fois que vous accrochez un survivant autre que votre obsession, si elle est en vie, vous gagnez un jeton. Si l’obsession est en vie, tous les autres survivants reçoivent une pénalité de vitesse de réparation, de sabotage et de soins de 3 % pour chaque jeton. Le tueur ne peut être obsédé que par un survivant à la fois.", "fr": "Lumière mourante", "descEn": "You become obsessed with one Survivor. Your Obsession gains a 33% action speed bonus to unhooking and healing other Survivors. Each time you hook a Survivor other than the Obsession, if the Obsession is alive, gain a token. If the Obsession is alive, all Survivors who are not the Obsession get 3% penalty to repair, healing and sabotage speeds for each token. \"The Killer can only be obsessed with one Survivor at a time.", "descEs": "Te obsesionas con un superviviente. Tu obsesión obtiene un 33 % de bonificación en la velocidad de acción al desenganchar y curar a otros supervivientes. Cada vez que enganches a un superviviente que no sea la obsesión, si la obsesión sigue con vida, obtienes un distintivo. Si la obsesión sigue con vida, el resto de supervivientes sufre una penalización de velocidad en reparaciones, curaciones y sabotajes del 3 %. El asesino no puede obsesionarse con más de un superviviente.", "es": "Luz que agoniza", "charEn": "The Shape", "charFr": "La Silhouette", "charEs": "La Forma"},{"id": "theThirdSeal", "name": "Hex: The Third Seal", "side": "killer", "img": "data:image/png;base64,", "desc": "Un sort qui entrave la capacité de repérage d’auras. Frapper un survivant avec une attaque de base ou une attaque spéciale pendant que le totem ensorcelé est actif applique l’effet de statut Aveuglement. Cet effet s’applique aux 4 derniers survivants frappés. Les effets du sort persistent tant que le totem ensorcelé est en place. Aveuglement empêche les survivants de voir les auras.", "fr": "Sort : Le troisième sceau", "descEn": "A Hex that hinders one's aura reading ability. Hitting a Survivor with a basic attack or a special attack while the Hex Totem is active applies the Blindness status effect. This effect applies to the last 4 Survivors hit. The Hex effects persist as long as the related Hex Totem is standing. Blindness prevents Survivors from seeing auras.", "descEs": "Un maleficio que repercute negativamente en la capacidad de percepción de auras. Mientras el tótem de maleficio siga activo, cuando golpeas a un enemigo con un ataque básico o un ataque especial le provocas el efecto de estado Ceguera. Dicho efecto se mantiene en los últimos 4 supervivientes a los que hayas golpeado. Los efectos del maleficio perduran mientras su tótem de maleficio correspondiente siga en pie. Ceguera impide que los supervivientes vean auras.", "es": "Maleficio: El tercer sello", "charEn": "The Hag", "charFr": "La Harpie", "charEs": "La Bruja"},{"id": "overwhelmingPresence", "name": "Overwhelming Presence", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous savoir à proximité suffit à perturber vos victimes. Les survivants dans votre rayon de terreur souffrent d'inefficacité. Le taux de consommation d'objets des survivants affectés est augmenté de 100 %.", "fr": "Présence écrasante", "descEn": "Just knowing you are near is enough to disturb your victims. Survivors within your Terror Radius suffer from inefficiency. Affected Survivors' item consumption rates are increased by 100%.", "descEs": "Saber que estás cerca basta para perturbar a tus víctimas. Los supervivientes que se encuentren dentro de tu radio de terror se mueren de miedo y se vuelven más torpes. Los objetos de los supervivientes afectados se consumen un 100 % más rápido.", "es": "Presencia abrumadora", "charEn": "The Doctor", "charFr": "Le Docteur", "charEs": "El Doctor"},{"id": "monitorAndAbuse", "name": "Monitor & Abuse", "side": "killer", "img": "data:image/png;base64,", "desc": "Méticuleux dans votre approche, terrifiant dans son application. Tandis que vous pourchassez un survivant, votre rayon de terreur augmente de 8 mètres. Dans le cas contraire, il est réduit de 8 mètres et votre champ de vision s'élargit de 8 degrés. Les améliorations du champ de vision ne sont pas cumulables.", "fr": "Surveillance et maltraitance", "descEn": "Meticulous in your approach, terrifying in your application. While in a chase, your Terror Radius is increased by 8 meters. Otherwise, your Terror Radius is decreased by 8 meters and your field of view is increased by 8 degrees. Field of view gains do not stack.", "descEs": "Un acercamiento meticuloso y una aplicación aterradora. Durante una persecución, tu radio de terror aumenta 8 metros. En los demás casos, tu radio de terror disminuye 8 metros y tu campo de visión aumenta 8 grados. Las ventajas del campo de visión no se acumulan.", "es": "Monitorización y abuso", "charEn": "The Doctor", "charFr": "Le Docteur", "charEs": "El Doctor"},{"id": "generatorOvercharge", "name": "Overcharge", "side": "killer", "img": "data:image/png;base64,", "desc": "La haine du progrès vous anime. Surchargez un générateur en effectuant l'action Endommager le générateur. Le prochain survivant à interagir avec ce générateur doit faire face à un test d'habileté d'une difficulté énorme. Échouer au test d'habileté génère une perte de progression supplémentaire de 5 %. Réussir le test d'habileté ne génère aucune progression, mais empêche l'explosion du générateur.", "fr": "Surcharge", "descEn": "You are fuelled by your hate for progress. Overcharge a generator by performing the Damage Generator action. The next Survivor interacting with that generator is faced with a difficult Skill Check. Failing the Skill Check results in an additional 5% loss of progress. Succeeding the Skill Check grants no progress but prevents the generator explosion. After Overcharge is applied to a generator, its regression speed increases from 75% of normal to 200% of normal over the next 30 seconds.", "descEs": "Te impulsa el odio hacia que se arreglen los generadores. Al llevar a cabo la acción Dañar generador, lo sobrecargas. El próximo superviviente que interaccione con él se enfrentará a una prueba de habilidad tremendamente difícil. Si no la supera, el índice de reparación se revertirá un 5 % adicional. Si la supera, la cantidad arreglada no aumentará, pero sí evitará que el generador explote.", "es": "Sobrecarga", "charEn": "The Doctor", "charFr": "Le Docteur", "charEs": "El Doctor"},{"id": "beastOfPrey", "name": "Beast of Prey", "side": "killer", "img": "data:image/png;base64,", "desc": "Votre désir de tuer est si intense que vous perdez momentanément votre connexion avec l’Entité, ce qui vous rend totalement imprévisible. Octroie l’effet de statut Indétectable après l’obtention de Soif de sang palier 1. L’effet de statut est supprimé dès que vous perdez Soif de sang. Vous gagnez 50 % de points de sang supplémentaires en exécutant des actions de la catégorie Chasseur. Indétectable masque l'aura, le rayon de terreur et la marque rouge du tueur.", "fr": "Prédation", "descEn": "Your lust for a kill is so intense that your connection with The Entity is momentarily lost, making you totally unpredictable. Grants the Undetectable status effect after gaining Bloodlust Tier I. The status effect is removed once you lose Bloodlust. Gain 50% more Bloodpoints for actions in the Hunter Category. Undetectable hides the Killer's aura, Terror Radius, and Red Stain.", "descEs": "Tus ganas de matar son tan intensas que pierdes la conexión con el Ente por un instante y te vuelves totalmente impredecible. Aplica el efecto de estado Indetectable tras llegar a nivel I de Sed de sangre y se disipa en cuanto pierdes Sed de sangre. Obtienes un 50 % extra de puntos de sangre con acciones de la categoría Caza. Indetectable oculta el aura, el radio de terror y la marca roja del asesino.", "es": "Bestia de presa", "charEn": "The Huntress", "charFr": "La Chasseuse", "charEs": "La Cazadora"},{"id": "territorialImperative", "name": "Territorial Imperative", "side": "killer", "img": "data:image/png;base64,", "desc": "Renforce la capacité de repérage d'aura. Les auras des survivants vous sont révélées pendant 3 secondes lorsqu'ils entrent dans la cave et que vous vous trouvez à plus de 32 mètres de l'entrée de cette dernière. Instinct territorial ne peut être activé qu'une fois toutes les 20 secondes.", "fr": "Instinct territorial", "descEn": "Unlocks potential in one's aura reading ability. Survivors' auras are revealed to you for 3 seconds when they enter the basement and you are more than 32 meters away from the basement entrance. Territorial Imperative can only be triggered once every 20 seconds.", "descEs": "Permite percibir auras. Se te revelan las auras de los supervivientes durante 3 segundos cuando entran en el sótano y tú estás a más de 32 metros de distancia. Instinto territorial solo se puede activar una vez cada 20 segundos.", "es": "Instinto territorial", "charEn": "The Huntress", "charFr": "La Chasseuse", "charEs": "La Cazadora"},{"id": "huntressLullaby", "name": "Hex: Huntress Lullaby", "side": "killer", "img": "data:image/png;base64,", "desc": "Un sort qui puise sa force dans le désespoir. Votre traque devient une chanson entêtante qui trouble l’attention de vos proies. Les survivants subissent un malus de régression de 6 % quand ils ratent un test d’habileté en soignant ou en réparant. Chaque fois qu’un survivant est suspendu à un crochet, la Berceuse de la Chasseuse gagne en puissance et affecte les avertissements de tests d’habileté de soins et de réparations. 1 à 4 jetons : le délai entre le son d’avertissement du test d’habileté et ce dernier se raccourcit.5 jetons : aucun avertissement de test d’habileté. Les effets du sort persistent tant que le totem ensorcelé est debout.", "fr": "Sort : Berceuse de la Chasseuse", "descEn": "A Hex rooting its power in despair. Your hunt is an irresistible song of dread which muddles your prey's attention. Survivors receive a 6% regression penalty when missing a Skill Check while healing or repairing. Each time a Survivor is hooked, Huntress Lullaby grows in power. It affects healing and repairing Skill Check warnings: 1 to 4 Tokens: Time between the Skill Check warning sound and the Skill Check becomes shorter.5 Tokens: No Skill Check warning. The Hex effects persist as long as the related Hex Totem is standing.", "descEs": "Un maleficio que basa su poder en la pérdida de la esperanza. Cazas entonando una irresistible y funesta melodía que afecta a la capacidad de atención de tus presas. Los supervivientes sufren una penalización del 6 % de regresión si fallan una prueba de habilidad mientras están curando o reparando. Cada vez que cuelgas de un gancho a un superviviente, Nana de cazadora gana en poder. Repercute en las advertencias de las pruebas de habilidad de curación y reparación: De 1 a 4 distintivos: Se reduce el tiempo que transcurre entre el sonido de advertencia y la prueba de habilidad.5 distintivos: Se elimina el sonido de advertencia previo a las pruebas de habilidad. Los efectos del maleficio perduran mientras su tótem de maleficio correspondiente siga en pie.", "es": "Maleficio: Nana de cazadora", "charEn": "The Huntress", "charFr": "La Chasseuse", "charEs": "La Cazadora"},{"id": "knockOut", "name": "Knock Out", "side": "killer", "img": "data:image/png;base64,", "desc": "Le traumatisme causé par vos attaques brutales rend difficile le simple fait de crier à l’aide. L’aura des survivants, auxquels vous infligez l’état critique avec vos attaques de base, n’est pas révélée aux autres survivants s’ils se tiennent à plus de 15 mètres.Les survivants auxquels vous infligez l’état critique avec vos attaques de base rampent 50 % plus lentement pendant 16 secondes et leur vitesse de récupération est réduite de 25 %.Pendant ce temps, les survivants sont affectés par l’effet de statut Aveuglement. Aveuglement empêche les survivants de voir les auras.", "fr": "K.O.", "descEn": "The trauma caused by your brutal attacks makes crying for help painfully difficult. Survivors put into the dying state by your basic attacks are not revealed to other Survivors when they are standing outside of a 15-meter range.Survivors put into the dying state by your basic attacks crawl 50% slower for 16 seconds, and their recovery speed is reduced by 25%.During this time, Survivors are affected by the Blindness status effect. Blindness prevents Survivors from seeing auras.", "descEs": "El trauma causado por tus brutales ataques hace que pedir ayuda resulte extremadamente difícil. Los supervivientes que estén a más de 15 metros de distancia no verán a los supervivientes que hayas dejado agonizantes con ataques básicos.Los supervivientes que hayas dejado agonizantes con ataques básicos se arrastrarán un 50 % más lento a lo largo de 16 segundos y su velocidad de recuperación se reducirá un 25 %.Durante este tiempo, los supervivientes sufrirán el efecto de estado Ceguera. Ceguera impide que los supervivientes vean auras.", "es": "Noqueo", "charEn": "The Cannibal", "charFr": "Le Cannibale", "charEs": "El Caníbal"},{"id": "bBQAndChili", "name": "Barbecue & Chili", "side": "killer", "img": "data:image/png;base64,", "desc": "Un lien profond avec l'Entité débloque le potentiel de repérer les auras.Après avoir pendu un survivant à un crochet, les auras de tous les autres survivants vous sont révélées pendant 4 secondes s'ils sont à plus de 40 mètres du crochet.", "fr": "Chili et barbecue", "descEn": "A deep bond with The Entity unlocks potential in one's aura reading ability.After hooking a Survivor, all other Survivors' auras are revealed to you for 4 seconds when they are further than 40 meters from the hook.", "descEs": "Un profundo vínculo con el Ente te permite percibir auras.Tras colgar a un superviviente, podrás ver el aura del resto durante 4 segundos si están a más de 40 metros de distancia del gancho.", "es": "Barbacoa y chile", "charEn": "The Cannibal", "charFr": "Le Cannibale", "charEs": "El Caníbal"},{"id": "franklinsLoss", "name": "Franklin's Demise", "side": "killer", "img": "data:image/png;base64,", "desc": "Vos attaques de base forcent les survivants à lâcher leur objet à l’impact. S'il n'est pas ramassé, l’objet au sol perd toutes ses charges au bout de 90 secondes. Dévoile les objets au sol à moins de 32 mètres à l’aide d’une aura blanche. L’aura vire lentement au rouge jusqu’à ce que l’objet soit vidé de ses charges.", "fr": "Trépas de Franklin", "descEn": "Your basic attacks make Survivors drop their item on impact. While on the ground, it takes up to 90 seconds for the item to lose all of its charges if it is not picked up. Reveal items on the ground within 32 meters with a white aura. The Aura will slowly fade to red until the Item is empty of charges.", "descEs": "Tus ataques básicos obligan a los supervivientes a soltar los objetos que llevan encima. Cuando el objeto esté en el suelo, tardará hasta 90 segundos en perder todas sus cargas si no lo recogen. Un aura blanca mostrará los objetos del suelo que estén a un máximo de 32 metros. ¡Para! ¡Para!\". (Franklin)", "es": "Muerte de Franklin", "charEn": "The Cannibal", "charFr": "Le Cannibale", "charEs": "El Caníbal"},{"id": "fireUp", "name": "Fire Up", "side": "killer", "img": "data:image/png;base64,", "desc": "La tension accrue, due au fait de perdre votre proie, vous emplit de rage et vous procure un élan de motivation inattendu. Chaque fois qu’un survivant termine la réparation d’un générateur, Intensité ardente gagne en puissance. Pour chaque générateur réparé, vous obtenez un bonus cumulable de 4 % jusqu’à la fin de la partie sur la vitesse de ramassage, de lâcher, de saut d’obstacles, de destruction de palettes, de générateurs et des murs qui peuvent l’être.", "fr": "Intensité ardente", "descEn": "The increased pressure of losing your prey fills you with anger and gives you unsuspected motivation. Each time the Survivors complete repairs on a generator, Fire Up grows in power. For each generator completed, gain a 4% stackable buff that grants a speed bonus to picking up, dropping, vaulting, damaging generators, and breaking pallets and breakable walls for the remainder of the trial.", "descEs": "La presión añadida ante la posibilidad de perder a tus presas te imbuye de ira y te proporciona una motivación insospechada. Enfurecimiento crece en poder cada vez que un superviviente termina de reparar un generador. Por cada generador completado, recibes una bonificación acumulable de velocidad del 4 % durante el resto de la partida a la hora de recoger o soltar objetos, saltar, dañar generadores y romper palés o muros destruibles.", "es": "Enfurecimiento", "charEn": "The Nightmare", "charFr": "Le Cauchemar", "charEs": "La Pesadilla"},{"id": "rememberMe", "name": "Remember Me", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous devenez obsédé par un survivant. Chaque fois que votre obsession perd un état de santé, le temps d’ouverture des portes de sortie est augmenté de 4 secondes, jusqu’à un maximum de 16 secondes supplémentaires. L’obsession n’est pas affectée par Souviens-toi de moi. Le tueur ne peut être obsédé que par un survivant à la fois.", "fr": "Souviens-toi de moi", "descEn": "You become obsessed with one Survivor. Each time your Obsession loses a health state, you increase the opening time of the exit gates by 4 seconds up to a maximum of 16 additional seconds. The Obsession is not affected by Remember Me. The Killer can only be obsessed with one Survivor at a time.", "descEs": "Te obsesionas con un superviviente. Cada vez que tu obsesión pierde un estado de salud, aumentas en 4 segundos el tiempo que tardan en abrirse las puertas de salida, hasta un máximo de 16 segundos adicionales. La obsesión es inmune a Recuérdame. El asesino no puede obsesionarse con más de un superviviente.", "es": "Recuérdame", "charEn": "The Nightmare", "charFr": "Le Cauchemar", "charEs": "La Pesadilla"},{"id": "hangmansTrick", "name": "Hangman's Trick", "side": "killer", "img": "data:image/png;base64,", "desc": "Les modifications astucieuses que vous avez apportées aux crochets vous préviennent si on y touche. Vous recevez une alerte quand un survivant commence à saboter un crochet.Lorsque vous portez un survivant, vous voyez l’aura du moindre survivant à 6 mètres d’un crochet.", "fr": "Coup du pendu", "descEn": "Your ingenious modifications to hooks alert you of tampering. Gain a notification when a Survivor begins sabotaging a hook.While carrying a Survivor, see the aura of any Survivor within 6 meters of a hook.", "descEs": "Tus ingeniosas modificaciones para los ganchos te alertan cuando son manipulados. Si un superviviente empieza a sabotear un gancho, recibes una notificación.Mientras cargues con un superviviente, verás el aura de cualquier superviviente que esté a menos de 6 metros del gancho.", "es": "Truco del verdugo", "charEn": "The Pig", "charFr": "Le Cochon", "charEs": "La Cerda"},{"id": "surveillance", "name": "Surveillance", "side": "killer", "img": "data:image/png;base64,", "desc": "Renforce la capacité de repérage d'auras. Tous les générateurs inversés sont entourés d'une aura blanche. Si l'inversion est interrompue, le générateur se retrouve entouré d'une aura jaune pendant 16 secondes. Les bruits causés par la réparation d'un générateur sont audibles à 8 mètres de plus.", "fr": "Surveillance", "descEn": "Unlocks potential in one's aura reading ability. Any regressing generator will be highlighted by a white aura. If the regression is interrupted on a generator, it will be highlighted by a yellow aura for 16 seconds. Noises created by generator repairs are audible at an additional 8 meters.", "descEs": "Permite percibir auras. Los generadores que se estén revirtiendo se iluminan con un aura blanca. Cuando se revierten del todo, el aura se vuelve amarilla durante 16 segundos. La distancia a la que se percibe el ruido de las reparaciones aumenta 8 metros.", "es": "Supervisión", "charEn": "The Pig", "charFr": "Le Cochon", "charEs": "La Cerda"},{"id": "coulrophobia", "name": "Coulrophobia", "side": "killer", "img": "data:image/png;base64,", "desc": "Même ceux qui n'ont pas peur des clowns sont terrifiés face à vous. Les survivants dans votre rayon de terreur ont 50 % de malus de vitesse de progression des soins, et les tests d'habileté de soins bougent 50 % plus vite.", "fr": "Coulrophobie", "descEn": "Even those without a fear of clowns know to be terrified of you. Survivors within your Terror Radius have a 50% penalty to healing progression speed, and healing Skill Checks move 50% faster.", "descEs": "Aterrorizarás incluso a quienes no tengan coulrofobia. Los supervivientes que se encuentren dentro de tu radio de terror sufren una penalización del 50 % en su velocidad de curación, y las pruebas de habilidad de curación se mueven un 50 % más rápido.", "es": "Coulrofobia", "charEn": "The Clown", "charFr": "Le Clown", "charEs": "El Payaso"},{"id": "hatred", "name": "Rancor", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous devenez obsédé par un survivant. Chaque fois qu'un générateur est terminé, l'obsession voit votre aura pendant 3 secondes . Chaque fois qu'un générateur est terminé, les positions de tous les survivants vous sont révélées pendant 3 secondes . Une fois tous les générateurs terminés, l'obsession possède l'effet de statut À découvert et le tueur peut éliminer l'obsession. Le tueur ne peut être obsédé que par un survivant à la fois.", "fr": "Rancœur", "descEn": "You become obsessed with one Survivor. Each time a generator is completed, your Obsession sees your aura for 3 seconds. Each time a generator is completed, all Survivors' locations are revealed to you for 3 seconds. Once all generators are completed, the Obsession has the Exposed status effect and you can kill your Obsession. The Killer can only be obsessed with one Survivor at a time.", "descEs": "Te obsesionas con un superviviente. Cada vez que se complete un generador, tu obsesión podrá ver tu aura durante 3 segundos. Cada vez que se complete un generador, podrás ver dónde se encuentran todos los supervivientes durante 3 segundos. En cuanto se completen todos los generadores, la obsesión pasa a sufrir el efecto de estado Vulnerabilidad, y el asesino podrá matarla. El asesino no puede obsesionarse con más de un superviviente.", "es": "Rencor", "charEn": "The Spirit", "charFr": "L'Esprit", "charEs": "El Espíritu"},{"id": "madGrit", "name": "Mad Grit", "side": "killer", "img": "data:image/png;base64,", "desc": "Quand vous portez un survivant, vous ne subissez pas de temps de récupération pour les attaques de base manquées, et toucher un autre survivant avec une attaque de base interrompt le chronomètre durant lequel le survivant porté peut se débattre pendant 4 secondes.", "fr": "Cran dément", "descEn": "While carrying a Survivor, you suffer no cooldown for missed basic attacks and successfully hitting another Survivor with a basic attack will pause the carried Survivor’s wiggle timer for 4 seconds.", "descEs": "Mientras cargas con un superviviente, los ataques básicos que falles no tendrán tiempo de recarga y, si logras golpear a otro superviviente, el temporizador de forcejeo del que llevas a cuestas se detendrá durante 4 segundos.", "es": "Furia ciega", "charEn": "The Legion", "charFr": "La Légion", "charEs": "La Legión"},{"id": "ironMaiden", "name": "Iron Maiden", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous ouvrez les casiers 50 % plus vite. Quand un survivant sort d’un casier, il souffre de l’effet de statut À découvert pendant 4 secondes et crie, ce qui révèle sa position pendant 30 secondes. Les survivants À découvert seront abattus par les attaques de base même s’ils ne sont pas blessés.", "fr": "Vierge de fer", "descEn": "You open lockers 50% faster. Survivors who exit lockers suffer from the Exposed status effect for 4 seconds and scream, revealing their location for 30 seconds. Exposed Survivors will be downed by basic attacks even if uninjured.", "descEs": "Abres taquillas un 50 % más rápido. Cuando un superviviente sale de una taquilla, se ve afectado por el efecto de estado Vulnerabilidad durante 4 segundos y grita, revelando su ubicación durante 30 segundos. Los supervivientes con Vulnerabilidad se derribarán con ataques básicos aunque no tengan heridas.", "es": "Doncella de hierro", "charEn": "The Legion", "charFr": "La Légion", "charEs": "La Legión"},{"id": "infectiousFright", "name": "Infectious Fright", "side": "killer", "img": "data:image/png;base64,", "desc": "Les cris des infidèles font bondir votre cœur. Les survivants présents dans votre rayon de terreur pendant qu’un autre survivant entre en état critique hurleront, vous révélant leur position pendant 6 secondes.", "fr": "Peur contagieuse", "descEn": "The cries of the unfaithful makes your heart leap. Any Survivors that are within your Terror Radius while another Survivor is put into the dying state will yell and reveal their location to you for 6 seconds.", "descEs": "Se te acelera el corazón al oír los gritos de los infieles. Cualquier superviviente que esté dentro de tu radio de terror cuando dejes agonizante a alguien gritará y te revelará su ubicación durante 6 segundos.", "es": "Terror contagioso", "charEn": "The Plague", "charFr": "L'Épidémie", "charEs": "La Plaga"},{"id": "darkDevotion", "name": "Dark Devotion", "side": "killer", "img": "data:image/png;base64,", "desc": "La démonstration de vos pouvoirs provoque un vent de panique qui gagne toute la région. Vous devenez obsédé par un survivant. Quand l'obsession perd un état de santé, vous lui transférez votre rayon de terreur pendant 32 secondes avec un rayon établi à 30 mètres. Vous bénéficiez de l’effet de statut Indétectable pendant toute cette durée. Le survivant avec le rayon de terreur transféré est également considéré comme étant « à l’intérieur du rayon de terreur » à toutes fins utiles. Le tueur ne peut être obsédé que par un seul survivant à la fois. Indétectable masque l'aura, le rayon de terreur et la marque rouge du tueur.", "fr": "Sombre dévotion", "descEn": "The display of your powers creates a whirlwind of panic that spreads throughout the land. You become obsessed with one Survivor. When the Obsession loses a health state, your Terror Radius transfers to the Obsession for 32 seconds, and its radius is set to 30 meters. You are granted the Undetectable status effect for the duration. The Survivor with the transferred Terror Radius is also considered to be \"inside the Terror Radius\" for other purposes. The Killer can only be obsessed with one Survivor at a time. Undetectable hides the Killer's aura, Terror Radius, and Red Stain.", "descEs": "Tu exhibición de poder genera una ola de pánico que se extiende por todo el terreno. Te obsesionas con un superviviente. Cuando la obsesión pierde un estado de salud, tu radio de terror se transfiere a la obsesión durante 32 segundos y lo establece en 30 metros. Mientras dure el efecto, se te aplica el efecto de estado Indetectable. El superviviente con el radio de terror transferido también se considera \"dentro del radio de terror\" a todos los efectos. El asesino no puede obsesionarse con más de un superviviente. Indetectable oculta el aura, el radio de terror y la marca roja del asesino.", "es": "Devoción oscura", "charEn": "The Plague", "charFr": "L'Épidémie", "charEs": "La Plaga"},{"id": "imAllEars", "name": "I'm All Ears", "side": "killer", "img": "data:image/png;base64,", "desc": "Vos sens sont aiguisés dans le sombre royaume de l’Entité. Débloque le potentiel de repérage d’aura d’une personne. L’aura de tout survivant effectuant une action précipitée à moins de 48 mètres de votre position est révélée pendant 6 secondes. Je vous écoute ne peut être déclenché qu’une fois toutes les 40 secondes.", "fr": "Je vous écoute", "descEn": "Your keen senses are sharpened in the dark realm of The Entity. Unlocks potential in one's aura reading ability. Any Survivor performing a rushed action within 48 meters from your location will have their aura revealed for 6 seconds. I'm All Ears can only be triggered once every 40 seconds.", "descEs": "Tus sentidos se agudizan en el reino oscuro del Ente. Permite percibir auras. El aura de cualquier superviviente que lleve a cabo una acción rápida dentro de una distancia de 48 metros se te revelará durante 6 segundos. Soy todo oídos solo se puede activar una vez cada 40 segundos.", "es": "Soy todo oídos", "charEn": "The Ghost Face", "charFr": "Ghost Face", "charEs": "Ghost Face"},{"id": "furtiveChase", "name": "Furtive Chase", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous devenez obsédé par un survivant. Vous guettez dans l’ombre, éliminant vos victimes les unes après les autres. Quand votre obsession est suspendue à un crochet, Poursuite furtive reçoit un jeton, jusqu'à un maximum de 4 jetons. Chaque jeton réduit votre rayon de terreur de 4 mètres pendant une poursuite. Quand un survivant sauve l’obsession d’un crochet, le sauveteur devient l’obsession. Le Tueur ne peut être obsédé que par un seul Survivant à la fois.", "fr": "Poursuite furtive", "descEn": "You become obsessed with one Survivor. You lurk in the shadows, eliminating your victims one by one. When your Obsession is hooked, Furtive Chase receives a token, up to a maximum of 4 tokens. Each token decreases your Terror Radius by 4 meters while in a chase. When a Survivor rescues the Obsession from a hook, the rescuer becomes the Obsession. \"The Killer can only be obsessed with one Survivor at a time.", "descEs": "Te obsesionas con un superviviente. Acechas en las sombras y eliminas a tus víctimas una a una. Cuando cuelgas a tu obsesión, Persecución furtiva recibe un distintivo, hasta un máximo de 4. Cada distintivo reduce tu radio de terror 4 metros durante una persecución. Cuando un superviviente rescata a tu obsesión de un gancho, el rescatador se convierte en tu obsesión. El asesino no puede tener más de una obsesión a la vez.", "es": "Persecución furtiva", "charEn": "The Ghost Face", "charFr": "Ghost Face", "charEs": "Ghost Face"},{"id": "mindBreaker", "name": "Fearmonger", "side": "killer", "img": "data:image/png;base64,", "desc": "Votre présence éprouvante épuise et affaiblit votre proie. Tout survivant réparant un générateur souffre des effets de statut Aveuglement et Épuisement. Si le survivant souffre déjà d’Épuisement, le compte à rebours de son effet de statut sera mis en pause. Les deux effets de statut durent secondes après l’arrêt des réparations.", "fr": "Semeur de peur", "descEn": "Your distressing presence drains and weakens your prey. Any Survivor repairing a generator, suffers from the Blindness and Exhausted status effect. If the Survivor is already Exhausted, their status effect's timer will be paused. Both status effects linger for seconds after stopping repairs.", "descEs": "Tu inquietante presencia agota y debilita a tu presa. Todos los supervivientes que reparan un generador sufren los efectos de estado Ceguera y Agotamiento. Si el superviviente ya sufre Agotamiento, se detendrá el temporizador de su efecto de estado. Ambos efectos de estado se mantendrán durante segundos después de terminar las reparaciones.", "es": "Hacedor de miedo", "charEn": "", "charFr": "", "charEs": ""},{"id": "cruelConfinement", "name": "Claustrophobia", "side": "killer", "img": "data:image/png;base64,", "desc": "Vos liens avec l’Entité se manifestent lorsque votre proie tente de s'échapper. Chaque fois qu'un générateur est réparé, les fenêtres et sauts d'obstacles qui se trouvent à moins de 32 mètres sont verrouillés pour tous les survivants pendant les 30 secondes suivantes.", "fr": "Claustrophobie", "descEn": "Your ties to The Entity manifest when your prey attempts to get away. Each time a generator is repaired, all windows and vault locations within 32 meters of it are blocked for all Survivors for the next 30 seconds.", "descEs": "El vínculo con el Ente se manifiestan cuando tu presa trata de huir. Cada vez que se repara un generador, se bloquearán todas las ventanas y saltos en 32 metros de este para todos los supervivientes durante 30 segundos.", "es": "Claustrofobia", "charEn": "", "charFr": "", "charEs": ""},{"id": "surge", "name": "Jolt", "side": "killer", "img": "data:image/png;base64,", "desc": "Votre présence inquiétante électrise l’air ambiant et interfère avec la technologie. Plonger un survivant en état critique avec une attaque de base provoque l’explosion immédiate de tous les générateurs dans un rayon de 32 mètres et la perte immédiate de 32 % de leur progression.", "fr": "Secousse", "descEn": "Your eerie presence charges the air and interferes with technology. Putting a Survivor into the dying state with a basic attack causes all generators within a 32-meter radius to explode instantly and begin regressing. Generators affected by Jolt immediately lose 32% of their progress.", "descEs": "Los generadores afectados por Sacudida pierden inmediatamente un 32 % de su progreso.", "es": "Sacudida", "charEn": "", "charFr": "", "charEs": ""},{"id": "zanshinTactics", "name": "Zanshin Tactics", "side": "killer", "img": "data:image/png;base64,", "desc": "Débloque le potentiel de repérage d'aura. Vous faites preuve de vigilance et restez attentif aux zones clés du champ de bataille. Vous voyez l’aura de l’ensemble des palettes, murs destructibles et emplacements de saut d’obstacles dans un rayon de 32 mètres.", "fr": "Tactiques de Zanshin", "descEn": "Unlocks potential in one's aura reading ability. You are mentally alert and aware of key points on the battlefield. The auras of all pallets, breakable walls, and vault locations are revealed to you within a 32 meter range.", "descEs": "Permite percibir auras. Estás alerta mentalmente y te conoces los puntos clave del campo de batalla. Las auras de todos los palés, muros destruibles y saltos se te revelan a una distancia de 32 metros.", "es": "Tácticas de zanshin", "charEn": "The Oni", "charFr": "L’Oni", "charEs": "El Oni"},{"id": "bloodEcho", "name": "Blood Echo", "side": "killer", "img": "data:image/png;base64,", "desc": "L’agonie d’un survivant est infligée aux autres. Lorsque vous suspendez un survivant, tous les survivants blessés souffrent des effets de statut Hémorragie et Épuisement pendant 45 secondes. Écho sanguin a un temps de rechargement de 60 secondes. Épuisement empêche les survivants d’activer des compétences épuisantes. Hémorragie fait régresser la progression des soins quand les soins ne sont pas administrés et augmente les traces de sang laissées par les survivants blessés.", "fr": "Écho sanguin", "descEn": "The agony of one is inflicted on others. When hooking a Survivor, all other injured Survivors suffer from the Hemorrhage and Exhaustion status effect for 45 seconds. Blood Echo has a cooldown of 60 seconds. Exhausted prevents Survivors from activating exhausting perks. Hemorrhage regresses healing progress when not healing, and increases blood trails left by injured Survivors.", "descEs": "La agonía se vuelve contagiosa. Al colgar a un superviviente, todos los supervivientes heridos se ven afectados por los efectos de estado Hemorragia y Agotamiento durante 45 segundos. Eco sangriento tiene un tiempo de recarga de 60 segundos. Agotamiento impide que los supervivientes activen habilidades de este tipo. Hemorragia revierte el progreso de curación cuando no se está curando y aumenta el rastro de sangre que dejan los supervivientes heridos.", "es": "Eco sangriento", "charEn": "The Oni", "charFr": "L’Oni", "charEs": "El Oni"},{"id": "gearHead", "name": "Gearhead", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous avez l’œil pour du matériel en bon état. Quand un survivant perd un état de santé, Bricolo s’active. Quand Bricolo est actif, chaque fois qu’un survivant effectue un excellent test d’habileté pendant une réparation, vous voyez son aura pendant 10 secondes.", "fr": "Bricolo", "descEn": "You’ve got an ear for well-oiled gears. After a Survivor loses a health state, Gearhead activates. While Gearhead is active, each time a Survivor completes a Great Skill Check while repairing, their aura is revealed to you for 10 seconds.", "descEs": "Tienes oído para detectar cuándo funcionan a la perfección las máquinas. Después de que un superviviente pierda un estado de salud, Oído para la maquinaria se activa. Mientras Oído para la maquinaria esté activa, cada vez que un superviviente supere una prueba de habilidad excelente mientras repare, se revelará su aura durante 10 segundos.", "es": "Oído para la maquinaria", "charEn": "The Deathslinger", "charFr": "Le Lance-mort", "charEs": "El Arponero"},{"id": "deadManSwitch", "name": "Dead Man’s Switch", "side": "killer", "img": "data:image/png;base64,", "desc": "Lorsque vous suspendez un survivant à un crochet, Dispositif de l’homme mort s’active pendant 45 secondes. Une fois activé, tout survivant qui s’arrête avant d’avoir entièrement réparé le générateur fait que l’Entité bloque ce dernier jusqu’à la fin de l’effet de Dispositif de l’homme mort. Les générateurs affectés sont entourés d’une aura blanche.", "fr": "Dispositif de l’homme mort", "descEn": "When you hook a Survivor, Dead Man’s Switch activates for the next 45 seconds. While activated, any Survivor that stops repairing a generator before it is fully repaired causes The Entity to block the generator until Dead Man’s Switch's effect ends. Affected generators are highlighted by a white aura.", "descEs": "Cuando enganchas a un superviviente, se activa Interruptor del hombre muerto durante los próximos 45 segundos. Mientras esté activo, cualquier superviviente que deje de reparar un generador antes de que esté completamente reparado hace que el Ente bloquee el generador hasta que acabe el efecto de Interruptor de hombre muerto. Los generadores afectados se iluminarán con un aura blanca.", "es": "Interruptor del hombre muerto", "charEn": "The Deathslinger", "charFr": "Le Lance-mort", "charEs": "El Arponero"},{"id": "hexRetribution", "name": "Hex: Retribution", "side": "killer", "img": "data:image/png;base64,", "desc": "Un sort qui se déclenche au moment de sa destruction. Ceux qui vous contrarient seront punis. Tout survivant qui interagit avec un totem passif ou ensorcelé subira l’effet de statut Inconscient pendant 45 secondes. Si un totem ensorcelé est retiré, y compris celui-ci, l’aura de tous les survivants est révélée pendant 15 secondes. Inconscient empêche les survivants d'entendre ou d'être affectés par le rayon de terreur du tueur.", "fr": "Sort : Châtiment", "descEn": "A Hex that lashes out upon its destruction. Those who cross you will be punished. Any Survivor interacting with a Dull Totem or a Hex Totem will suffer from the Oblivious status effect for 45 seconds. If any Hex Totem is removed, including this one, the auras of all Survivors are revealed for 15 seconds. Oblivious prevents Survivors from hearing or being affected by the Killer's Terror Radius.", "descEs": "Un maleficio que se desata cuando se la destruye. Aquellos que te contraríen serán castigados. Cualquier superviviente que interactúe con un tótem apagado o un tótem de maleficio sufrirá el efecto de estado Inconsciencia durante 45 segundos. Si se elimina cualquier tótem de maleficio, incluido este, se revelarán las auras de todos los supervivientes durante 15 segundos. Inconsciencia impide que los supervivientes escuchen o les afecte el radio de terror del asesino.", "es": "Maleficio: Represalias", "charEn": "The Deathslinger", "charFr": "Le Lance-mort", "charEs": "El Arponero"},{"id": "forcedPenance", "name": "Forced Penance", "side": "killer", "img": "data:image/png;base64,", "desc": "Ceux qui se mettent en travers du devoir tombe sous le coup d’un terrible jugement. Les survivants qui subissent un coup de protection souffrent de l’effet de statut Brisé pendant 80 secondes.. Brisé empêche les survivants de recevoir des soins.", "fr": "Pénitence forcée", "descEn": "Those who stand in the way of duty will suffer harsh judgment. Survivors who take a protection hit are inflicted with the Broken status effect for 80 seconds. Broken prevents Survivors from being healed.", "descEs": "Quienes se interpongan en el camino del deber sufrirán una dura sentencia. Los supervivientes que reciben un golpe por protección sufren el efecto de estado Desesperanza durante 80 segundos. Desesperanza impide que los supervivientes se curen.", "es": "Imposición de penitencia", "charEn": "The Executioner", "charFr": "Le Bourreau", "charEs": "El Verdugo"},{"id": "trailOfTorment", "name": "Trail of Torment", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous guidez vos victimes sur un chemin de souffrance et châtiment. Après avoir endommagé un générateur, vous devenez Indétectable jusqu’à ce que le générateur cesse de régresser, ou bien qu’un survivant soit blessé ou mis en état critique. Pendant ce temps, l’aura jaune du générateur est révélée aux survivants. Cet effet ne peut être activé qu’une seule fois toutes les secondes.. Indétectable dissimule l’aura, le rayon de terreur et la tache rouge du tueur.", "fr": "Piste de souffrance", "descEn": "You guide your victims along a path of pain and punishment. After damaging a generator, you become Undetectable until the generator stops regressing or a Survivor is injured or put into the dying state by any means. During this time, the generator’s yellow aura is revealed to Survivors. This effect can only trigger once every seconds. Undetectable hides the Killer's aura, Terror Radius, and Red Stain.", "descEs": "Guías a tus víctimas por un camino de dolor y castigo. Tras dañar un generador, se te aplica el efecto Indetectable hasta que el progreso del generador deje de revertirse o hasta que un superviviente quede herido o agonizante del modo que sea. Durante este tiempo, los supervivientes podrán ver el aura amarilla del generador. Este efecto solo se puede activar una vez cada segundos. Indetectable oculta el aura, el radio de terror y la marca roja del asesino.", "es": "Rastro de tormento", "charEn": "The Executioner", "charFr": "Le Bourreau", "charEs": "El Verdugo"},{"id": "deathbound", "name": "Deathbound", "side": "killer", "img": "data:image/png;base64,", "desc": "Ceux dont la vie est entrelacée dans les ténèbres sont destinés à souffrir ensemble. Quand un survivant soigne un état de santé d’un autre survivant à au moins 32 mètres du tueur, le survivant qui effectue l’action de soin se met à crier, révélant leur position et activant Lien mortel pendant les 60 secondes suivantes. Pendant ce temps, le survivant souffre de l’effet de statut Inconscient quand il est à plus de 8 mètres du survivant soigné.br> Inconscient empêche les survivants d'entendre ou d'être affectés par le rayon de terreur du tueur.", "fr": "Lien mortel", "descEn": "Those whose lives are intertwined in darkness are destined to suffer together. When a Survivor heals another Survivor for one health state at least 32 meters away from the Killer, the Survivor performing the healing action will scream, revealing their location and activating Deathbound for the next 60 seconds. During that time, the Survivor will suffer from the Oblivious status effect when further than 8 meters away from the healed Survivor. Oblivious prevents Survivors from hearing or being affected by the Killer's Terror Radius.", "descEs": "Aquellos cuyas vidas se entrelazan en la oscuridad están destinados a sufrir juntos. Cuando un superviviente cura un estado de salud a otro a al menos 32 metros del asesino, el superviviente que esté realizando la curación gritará, revelará su ubicación y activará Vínculo mortal durante los siguientes 60 segundos. Durante ese tiempo, el superviviente sufrirá el efecto de estado Inconsciencia cuando esté a más de 8 metros del superviviente al que ha curado. Inconsciencia impide que los supervivientes escuchen o les afecte el radio de terror del asesino.", "es": "Vínculo mortal", "charEn": "The Executioner", "charFr": "Le Bourreau", "charEs": "El Verdugo"},{"id": "dragonsGrip", "name": "Dragon’s Grip", "side": "killer", "img": "data:image/png;base64,", "desc": "Après avoir endommagé un générateur, le premier survivant qui interagit avec dans les 30 prochaines secondes se met à crier, dévoilant sa position pendant 4 secondes, et il souffre de l’effet de statut À découvert pendant 60 secondes. Prise du dragon a un temps de recharge de 80 secondes. Les survivants À découvert seront abattus par les attaques de base même s’ils ne sont pas blessés.", "fr": "Prise du dragon", "descEn": "After damaging a generator, for the next 30 seconds, the first Survivor that interacts with it will scream, revealing their location for 4 seconds, and becoming afflicted with the Exposed status effect for 60 seconds. Dragon’s Grip has a cooldown of 80 seconds. Exposed Survivors will be downed by basic attacks even if uninjured.", "descEs": "Tras dañar un generador, el primer superviviente que interaccione con él durante los siguientes 30 segundos gritará, revelará su ubicación durante 4 segundos y sufrirá el efecto de estado Vulnerabilidad durante 60 segundos. Agarre del dragón tiene un tiempo de recarga de 80 segundos. Los supervivientes con Vulnerabilidad se derribarán con ataques básicos aunque no tengan heridas.", "es": "Agarre del dragón", "charEn": "The Blight", "charFr": "Le Fléau", "charEs": "El Deterioro"},{"id": "hexBloodFavor", "name": "Hex: Blood Favor", "side": "killer", "img": "data:image/png;base64,", "desc": "Un sort qui obtient les faveurs de l’Entité quand du sang est versé. Blesser un survivant invoque l’Entité pour bloquer les palettes dans un rayon de 32 mètre(s) autour de la position du survivant pendant 15 secondes. Les effets du sort persistent tant que le totem ensorcelé est debout.", "fr": "Sort : Faveur de sang", "descEn": "A Hex that gains The Entity’s favor when blood is spilled. Injuring a Survivor will call upon The Entity to block pallets from being pulled down within a 32 meter radius of the Survivor location for 15 seconds. The Hex effects persist as long as the related Hex Totem is standing.", "descEs": "Un maleficio que te hace ganarte el favor del Ente al derramar sangre. Al herir a un superviviente llamará al Ente para que impida que se derriben los palés que estén a un máximo de 32 metro(s) de la ubicación del superviviente durante 15 segundos. El efecto del maleficio perdura mientras su tótem de maleficio correspondiente siga en pie.", "es": "Maleficio: Favor de sangre", "charEn": "The Blight", "charFr": "Le Fléau", "charEs": "El Deterioro"},{"id": "hexUndying", "name": "Hex: Undying", "side": "killer", "img": "data:image/png;base64,", "desc": "Pendant que le Sort : Immortel est actif, l’aura des survivants à moins de 4 mètres d’un totem passif est révélée. Quand un autre totem ensorcelé est purifié, le sort de ce totem est transféré au totem Sort : Immortel, désactivant ce sort. Tous les jetons du sort transféré le sont également.", "fr": "Sort : Immortel", "descEn": "While Hex: Undying is active, Survivors within 4 meters of any Dull Totem have their aura revealed. When another Hex Totem is cleansed, that Totem's Hex transfers to the Hex: Undying Totem, deactivating Hex: Undying. Any tokens the transferred Hex had are transferred as well.", "descEs": "Mientras Maleficio: Inmortal esté activo, se revelarán las auras de los supervivientes que se encuentren a una distancia máxima de 4 metros de cualquier tótem apagado. Si alguien purifica un tótem de maleficio distinto, el maleficio vinculado de este último se transferirá al tótem de Maleficio: Inmortal, sustituyéndolo. Los distintivos que tuviera el maleficio de origen también se transfieren.", "es": "Maleficio: Inmortal", "charEn": "The Blight", "charFr": "Le Fléau", "charEs": "El Deterioro"},{"id": "hoarder", "name": "Hoarder", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous protégez le peu que vous avez et vous êtes attentif à toute activité dans vos réserves. Les survivants dévoilent leur position quand ils interagissent avec un coffre ou lorsqu’ils ramassent un objet à moins de 64 mètres de votre position. La partie commence avec un maximum de 2 coffres supplémentaires sur la carte.", "fr": "Amasseur", "descEn": "You protect what little you have and are attentive to any disturbance of your stockpiles. Survivors reveal their location when they interact with a chest or when they pick up an item within 64 meters of your location. The trial begins with up to 2 additional chests in the environment.", "descEs": "Proteges lo poco que tienes y prestas atención a la más mínima injerencia con tus posesiones. Los supervivientes revelan su posición cuando interaccionen con un cofre o recojan un objeto a una máxima de 64 metros de tu ubicación. La partida comienza con hasta 2 cofres adicionales en el entorno.", "es": "Acaparadora", "charEn": "The Twins", "charFr": "Les Jumeaux", "charEs": "Los Mellizos"},{"id": "oppression", "name": "Oppression", "side": "killer", "img": "data:image/png;base64,", "desc": "La vie n’a pas été tendre avec vous, et vous le rendez bien aux autres. Lorsque vous endommagez un générateur, un maximum de 3 autres générateurs aléatoires régressent également. Si les générateurs affectés sont en cours de réparation, tout survivant en train de les réparer doit effectuer un test d’habileté difficile. Oppression a un temps de recharge de 80 secondes.", "fr": "Oppression", "descEn": "Life has been difficult for you, so you’ll make it difficult for others. When you damage a generator, up to 3 other random generators also begin regressing. If the affected generators are being repaired, any Survivors repairing them receive a difficult Skill Check. Oppression has a cooldown of 80 seconds.", "descEs": "Como la vida no te ha tratado bien, quieres complicársela al resto del mundo. Cuando dañes un generador, se revertirá el progreso de hasta 3 generadores aleatorios. Si se está reparando alguno de esos generadores, activa una prueba de habilidad difícil para cada superviviente involucrado. Opresión tiene un tiempo de recarga de 80 segundos.", "es": "Opresión", "charEn": "The Twins", "charFr": "Les Jumeaux", "charEs": "Los Mellizos"},{"id": "starstruck", "name": "Starstruck", "side": "killer", "img": "data:image/png;base64,", "desc": "Votre sens inégalé de la mise en scène éblouit tout le monde. Quand vous portez un survivant, tout autre survivant dans votre rayon de terreur subit l’effet de statut À découvert. L’effet persiste pendant 30 secondes sur les survivants qui quittent votre rayon de terreur, et sur ceux dans le rayon lorsque vous suspendez ou relâchez le survivant porté. Fascination a un temps de recharge de 30 secondes une fois que vous ne portez plus le survivant. Les survivants À découvert seront abattus par les attaques de base même s’ils ne sont pas blessés.", "fr": "Fascination", "descEn": "Your unmatched showmanship dazzles all. While carrying a Survivor, any other Survivors within your Terror Radius suffer from the Exposed status effect. The effect persists for 30 seconds on Survivors who leave your Terror Radius, as well as those within the radius when you hook or release the carried Survivor. Starstruck has a cooldown of 30 seconds once a Survivor is no longer carried. Exposed Survivors will be downed by basic attacks even if uninjured.", "descEs": "Tu carisma sin parangón deja deslumbrados a todos. Al llevar a un superviviente, los demás supervivientes en tu radio de terror sufrirán el efecto de estado Vulnerabilidad. El efecto dura 30 segundos en aquellos supervivientes que se alejen de tu radio de terror o permanezcan en él cuando cuelgues o sueltes al superviviente al que llevas. Deslumbrado tiene un tiempo de recarga de 30 segundos cuando ya no lleves a un superviviente. Los supervivientes con Vulnerabilidad se derribarán con ataques básicos aunque no tengan heridas.", "es": "Deslumbrado", "charEn": "The Trickster", "charFr": "Le Farceur", "charEs": "El Traicionero"},{"id": "hexCrowdControl", "name": "Hex: Crowd Control", "side": "killer", "img": "data:image/png;base64,", "desc": "Un sort qui fait en sorte que ceux qui vous sont inférieurs soient correctement guidés. L’Entité bloque une fenêtre pendant 14 secondes après qu’un survivant a fait un saut précipité au travers. Les effets du sort persistent tant que le Totem ensorcelé est debout.", "fr": "Sort : Contrôle des foules", "descEn": "A Hex that ensures those lesser than you are properly herded. The Entity blocks a window for 14 seconds after a Survivor performs a rushed vault through it. The Hex effects persist as long as the related Hex Totem is standing.", "descEs": "Un maleficio que asegura una manipulación absoluta a quienes son inferiores a ti. El Ente bloquea una ventana durante 14 segundos cuando un superviviente realiza un salto acelerado a través de ella. Los efectos del maleficio perduran mientras su tótem de maleficio correspondiente siga en pie.", "es": "Maleficio: Control de masas", "charEn": "The Trickster", "charFr": "Le Farceur", "charEs": "El Traicionero"},{"id": "noWayOut", "name": "No Way Out", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous n’allez pas laisser n’importe qui accéder au carré VIP. Après avoir suspendu un survivant à un crochet pour la première fois, Aucune issue gagne un jeton. Une fois les portes de sortie alimentées, Aucune issue s’active. Quand un survivant interagit avec un interrupteur de porte de sortie, vous recevez une alerte sous forme d'une notification sonore. L’Entité bloque alors les deux interrupteurs de la porte de sortie pendant 8 secondes, plus 42 secondes supplémentaires pour chaque jeton en votre possession.", "fr": "Aucune issue", "descEn": "You're not going to let just anyone into the VIP room. After hooking a Survivor for the first time, No Way Out gains a token. Once the exit gates have been powered, No Way Out activates. When a Survivor interacts with an exit gate switch, you receive a loud noise notification. The Entity then blocks both exit gate switches for 8 seconds, plus an additional 42 seconds for each token in your possession.", "descEs": "No todo el mundo puede acceder a la sala vip, obviamente. Tras colgar a un superviviente por primera vez, Sin escapatoria gana un distintivo. Cuando se pongan en marcha las puertas de salida, se activará Sin escapatoria. Cuando un superviviente interactúa con el interruptor de una puerta de salida, recibes una notificación de ruido intenso. A continuación, el Ente bloquea ambos interruptores de la puerta de salida durante 8 segundos y 42 segundos adicionales por cada distintivo que tengas.", "es": "Sin escapatoria", "charEn": "The Trickster", "charFr": "Le Farceur", "charEs": "El Traicionero"},{"id": "hysteria", "name": "Hysteria", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous savez comment maltraiter un membre d’une équipe pour provoquer la panique. Lorsqu’un survivant est blessé par n’importe quel moyen, tous les survivants blessés souffrent de l’effet de statut Inconscient pendant 30 secondes. Hystérie peut uniquement être déclenchée toutes les 30 secondes. Inconscient empêche les survivants d'entendre ou d'être affectés par le rayon de terreur du tueur. « Désolé d’être un peu nerveux. Je ne savais pas trop à quoi m’attendre. » — Robert Kendo", "fr": "Hystérie", "descEn": "You know how to brutalize one member of a team to cause a panic. Whenever a healthy Survivor becomes injured by any means, all injured Survivors suffer from the Oblivious status effect for 30 seconds. Hysteria can only trigger once every 30 seconds. Oblivious prevents Survivors from hearing or being affected by the Killer's Terror Radius. \"Sorry I got a little jumpy there. Didn't know quite what to expect.\" —Robert Kendo", "descEs": "Sabes cómo agredir al miembro de un equipo para desatar el pánico. Cuando provocas una herida a un superviviente ileso del modo que sea, todos los supervivientes heridos sufren el efecto de estado Inconsciencia durante 30 segundos. Histeria solo se puede activar una vez cada 30 segundos. Inconsciencia impide que los supervivientes escuchen o les afecte el radio de terror del asesino. \"Perdona, me he puesto un poco nervioso. No sabía qué esperarme\". (Robert Kendo)", "es": "Histeria", "charEn": "The Nemesis", "charFr": "Le Nemesis", "charEs": "Némesis"},{"id": "hexPlaything", "name": "Hex: Plaything", "side": "killer", "img": "data:image/png;base64,", "desc": "Un sort qui joue sur la souffrance de sa victime. La première fois où vous suspendez un survivant à un crochet, il subit Malédiction et le Sort : Jouet s’active sur un totem passif. Le survivant maudit souffre de l’effet de statut Inconscient jusqu’à ce que le Sort : Jouet soit purifié. L’aura du totem affecté par le Sort : Jouet est dévoilée au survivant maudit lorsqu’il s’en trouve à moins de 16 mètres. Pendant les premières 90 secondes, seul le survivant maudit peut purifier le totem. Inconscient empêche les survivants d'entendre ou d'être affectés par le rayon de terreur du tueur.", "fr": "Sort : Jouet", "descEn": "A Hex that toys with a victim's suffering. The first time you hook a Survivor, they become Cursed and Hex: Plaything activates on a Dull Totem. The Cursed Survivor suffers from the Oblivious status effect until Hex: Plaything is cleansed. Hex: Plaything's totem aura is revealed to the Cursed Survivor when within 16 meters of it. For the first 90 seconds, only the Cursed Survivor can cleanse the totem. Oblivious prevents Survivors from hearing or being affected by the Killer's Terror Radius.", "descEs": "Un maleficio que juega con el sufrimiento de su víctima. La primera vez que cuelgas a un superviviente, este sufre Maldición, y Maleficio: Juguete se activa en un tótem apagado. El superviviente con Maldición sufre el efecto de estado Inconsciencia hasta que Maleficio: Juguete se purifica. El aura del tótem de Maleficio: Juguete se revela al superviviente con Maldición cuando esté a 16 metros de él. Durante los primeros 90 segundos, el superviviente con Maldición es el único que puede purificar el tótem. Inconsciencia impide que los supervivientes escuchen o les afecte el radio de terror del asesino.", "es": "Maleficio: Juguete", "charEn": "The Cenobite", "charFr": "Le Cénobite", "charEs": "El Cenobita"},{"id": "scourgeHookGiftOfPain", "name": "Scourge Hook: Gift of Pain", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous apportez la douce douleur. Au début de la partie, jusqu’à 4 crochets aléatoires sont changés en crochets flagellateurs. Vous voyez leur aura en blanc. Quand un survivant est libéré d’un crochet flagellateur, il souffre des effets de statut Hémorragie et Estropiement jusqu’à ce qu’il soit complètement soigné. La première fois que le survivant est soigné, il subit une pénalité de 9 % à la vitesse des soins et des réparations jusqu’à ce qu’il soit de nouveau blessé. Hémorragie fait régresser la progression des soins quand les soins ne sont pas administrés et augmente les traces de sang laissées par les survivants blessés. Estropiement augmente le temps requis pour guérir de 25 % et dure jusqu’à guérison complète. « Nous déchirerons votre âme. » — Pinhead", "fr": "Crochet flagellateur : Don de souffrance", "descEn": "You are the bringer of sweet pain. At the start of the trial, up to 4 random hooks are changed into scourge hooks. You see their auras in white. When a Survivor is unhooked from a scourge hook, they suffer from the Hemorrhage and Mangled status effect until fully healed. The first time the Survivor is healed, they suffer a 9% speed penalty to healing and repairing actions until injured again. Hemorrhage regresses healing progress when not healing, and increases blood trails left by injured Survivors. Mangled increases time required to heal by 25% and lasts until fully healed.", "descEs": "Te encargas de proporcionar un dolor muy dulce. Al comienzo de la partida, hasta 4 ganchos aleatorios pasarán a ser ganchos flagelantes. Puedes ver sus auras de color blanco. Cuando se descuelga a un superviviente de un gancho flagelante, sufrirá los efectos de estado Hemorragia y Laceración hasta que se cure por completo. La primera vez que se cura al sobreviviente, sufre una penalización del 9 % en acciones de curación y reparación hasta que le vuelvan a herir. Hemorragia revierte el progreso de curación cuando no se está curando y aumenta el rastro de sangre que dejan los supervivientes heridos. Laceración aumenta el tiempo que tarda en curarse un 25 % y dura hasta que se cure por completo.", "es": "Gancho flagelante: Obsequio doloroso", "charEn": "The Cenobite", "charFr": "Le Cénobite", "charEs": "El Cenobita"},{"id": "t_iconPerks_grimEmbrace", "name": "Grim Embrace", "side": "killer", "img": "data:image/png;base64,", "desc": "Votre acte de servitude envers l’Entité n’est pas passé inaperçu. Chaque fois qu'un survivant est suspendu à un crochet pour la première fois, vous gagnez un jeton. Après avoir atteint 4 jetons, Sombre étreinte s’active. L’Entité bloque tous les générateurs pendant 40 secondes. Vous voyez l’aura de l’obsession pendant 4 secondes. \"Le tueur ne peut être obsédé que par un survivant à la fois.", "fr": "Sombre étreinte", "descEn": "Your act of servitude to The Entity has not gone unnoticed. Each time a Survivor is hooked for the first time, you gain a token. Upon reaching 4 tokens Grim Embrace activates. The Entity blocks all generators for 40 seconds. The Obsession's aura is revealed to you for 4 seconds. \"The Killer can only be obsessed with one Survivor at a time.", "descEs": "Tus sacrificios por el Ente no han pasado desapercibidos. Cada vez que se cuelga por primera vez a un superviviente, obtienes un distintivo. Tras conseguir 4 distintivos, se activa Acogida nefasta. El Ente bloquea todos los generadores 40 segundos. Podrás ver el aura de la obsesión durante 4 segundos. El asesino no puede obsesionarse con más de un superviviente.", "es": "Acogida nefasta", "charEn": "The Artist", "charFr": "L’Artiste", "charEs": "La Artista"},{"id": "t_iconPerks_painResonance", "name": "Scourge Hook: Pain Resonance", "side": "killer", "img": "data:image/png;base64,", "desc": "Une douleur accablante résonne dans le chaos. Au début de la partie, jusqu’à 4 crochets aléatoires sont changés en crochets flagellateurs. Vous voyez leur aura en blanc. Quand un survivant est suspendu à un crochet flagellateur, le générateur avec la meilleure progression explose, perdant immédiatement 15 % de sa progression, et il commence à régresser.", "fr": "Crochet flagellateur : Écho de douleur", "descEn": "Overwhelming pain reverberates outwards into chaos. At the start of the trial, up to 4 random hooks are changed into scourge hooks. You see their auras in white. Any time a Survivor is hooked on a scourge hook, the generator with the most progress explodes, instantly losing 15% progress, and will start to regress.", "descEs": "Un dolor inconmensurable se convierte en un caos. Al comienzo de la partida, hasta 4 ganchos aleatorios pasarán a ser ganchos flagelantes. Puedes ver sus auras de color blanco. En cuanto se cuelgue a un superviviente de un gancho flagelante, el generador con más progreso explota, pierde un 15 % de progreso al instante y comenzará a revertirse.", "es": "Gancho flagelante: Dolor retumbante", "charEn": "The Artist", "charFr": "L’Artiste", "charEs": "La Artista"},{"id": "t_iconPerks_hexPentimento", "name": "Hex: Pentimento", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous réveillez le véritable pouvoir des totems, enfoui dans leurs vestiges. Vous voyez l’aura des totems détruits. Vous pouvez effectuer un rituel sur un totem détruit pour le raviver sous la forme d’un totem ensorcelé du Sort : Repentir. Pour chaque totem ensorcelé actif en même temps, Sort : Repentir obtient un effet supplémentaire. 1 totem ensorcelé : réduit la vitesse de réparation des survivants de 30 %.2 totems ensorcelés : réduit la vitesse de soins des survivants de 30 %.3 totems ensorcelés : réduit la vitesse de récupération des survivants après avoir été abattus de 30 %.4 totems ensorcelés : réduit la vitesse d’ouverture de la porte de sortie des survivants de 30 %.5 totems ensorcelés : Tous les totems sont bloqués par l’Entité. Quand un totem ensorcelé précédemment ravivé est retiré par n’importe quel moyen, ses vestiges sont consumés par l’Entité et il ne peut plus être ravivé.", "fr": "Sort : Repentir", "descEn": "You reveal the true power of the Totems, hidden within their remains. You see the aura of destroyed Totems. You can perform a ritual on a destroyed Totem to rekindle it as a Hex Totem for Hex: Pentimento. For each Hex Totem active at the same time, Hex: Pentimento gains an additional effect. 1 Hex Totem: Decreases Survivors' repair speed by 30%.2 Hex Totems: Decreases Survivors' healing speed by 30%.3 Hex Totems: Decreases Survivors' recovery speed from being downed by 30%.4 Hex Totems: Decreases Survivors' exit gate opening speed by 30%.5 Hex Totems: All Totems are blocked by the Entity. When a previously rekindled Hex Totem is removed by any means, its remains are consumed by The Entity and it cannot be rekindled again.", "descEs": "Puedes ver el verdadero poder de los tótems, oculto entre sus restos. Ves el aura de los tótems destruidos. Puedes practicar un ritual a un tótem destruido para reavivarlo en forma de tótem de maleficio para Maleficio: Pentimento. Por cada tótem de maleficio activado al mismo tiempo, Maleficio: Pentimento obtiene un efecto adicional. 1 tótem de maleficio: La velocidad de reparación de los supervivientes se reduce un 30 %.2 tótems de maleficio: La velocidad de curación de los supervivientes se reduce un 30 %.3 tótems de maleficio: La velocidad de recuperación de los supervivientes se reduce un 30 %.4 tótems de maleficio: La velocidad de apertura de puertas de salida de los supervivientes se reduce un 30 %.5 tótems de maleficio: El Ente bloquea todos los tótems. Cuando se elimina de cualquier modo un tótem de maleficio reavivado anteriormente, el Ente consume sus restos y no puede volver a reavivarse.", "es": "Maleficio: Pentimento", "charEn": "The Artist", "charFr": "L’Artiste", "charEs": "La Artista"},{"id": "floodOfRage", "name": "Scourge Hook: Floods of Rage", "side": "killer", "img": "data:image/png;base64,", "desc": "Vous formez une connexion psychique avec l'Entité et altérez les règles de la partie. Au début de la partie, jusqu’à 4 crochets aléatoires sont changés en crochets flagellateurs. Vous voyez leur aura en blanc. Quand un survivant est libéré d’un crochet flagellateur, l'aura de tous les survivants est révélée pendant 7 secondes.", "fr": "Crochet flagellateur : Flots de rage", "descEn": "You form a psychic connection with The Entity and alter the rules of the trial. At the start of the trial, up to 4 random hooks are changed into scourge hooks. You see their auras in white. When a Survivor is unhooked from a scourge hook, all other Survivors have their auras revealed for 7 seconds.", "descEs": "Estableces una conexión psíquica con el Ente y alteras las normas de la partida. Al comienzo de la partida, hasta 4 ganchos aleatorios pasarán a ser ganchos flagelantes. Puedes ver sus auras de color blanco. Cuando se desengancha a un superviviente de un gancho flagelante, los demás supervivientes revelan sus auras durante 7 segundos.", "es": "Gancho flagelante: Oleada de ira", "charEn": "The Onryō", "charFr": "L'Onryō", "charEs": "La Onryō"},{"id": "mercilessStorm", "name": "Merciless Storm", "side": "killer", "img": "data:image/png;base64,", "desc": "Tout le monde ressent votre horrible traumatisme. Quand un générateur atteint 90 % de progression, les survivants qui travaillent sur ce générateur se retrouvent confrontés à des tests d'habileté en continu. S'ils en ratent un ou interrompent leurs réparations, le générateur est bloqué par l'Entité pendant 20 secondes. Tempête impitoyable ne peut être déclenché qu'une fois par générateur par partie.", "fr": "Tempête impitoyable", "descEn": "Your horrible trauma is felt by everyone. When a generator reaches 90% progress, Survivors working on the generator will be faced with continuous Skill Checks. If they miss or stop repairing, the generator is blocked by the Entity for 20 seconds. Merciless Storm can only trigger once per generator per trial.", "descEs": "Todo el mundo siente tu espantoso trauma. Cuando un generador llega al 90 % de progreso, los supervivientes que estén reparando el generador deberán hacer frente a pruebas de habilidad continuas. Si fallan o dejan de repararlo, el Ente bloqueará el generador durante 20 segundos. Tormenta vil solo se puede activar una vez por generador y partida.", "es": "Tormenta vil", "charEn": "The Onryō", "charFr": "L'Onryō", "charEs": "La Onryō"},{"id": "dissolution", "name": "Dissolution", "side": "killer", "img": "data:image/png;base64,", "desc": "Tout se transforme en poussière. C'est aussi inévitable que la venue de la nuit. 20 secondes après avoir blessé un survivant par n'importe quel moyen, Dissolution s'active pendant 3 secondes. Tant que Dissolution est actif, si un survivant saute en courant par-dessus une palette dans votre rayon de terreur, l'Entité brisera la palette à l'issue du saut et Dissolution se désactivera.", "fr": "Dissolution", "descEn": "Everything turns to dust. It is as inescapable as the coming of the night. 20 seconds after injuring a Survivor by any means, Dissolution activates for 3 seconds. While Dissolution is active, if a Survivor fast vaults over a pallet inside of your Terror Radius, The Entity will break the pallet at the end of the vault, and Dissolution deactivates.", "descEs": "Polvo eres y en polvo te convertirás. Es tan inevitable como la llegada de la noche. 20 segundos después de herir a un superviviente del modo que sea, se activa Disolución durante 3 segundos. Mientras Disolución está activa, si un superviviente realiza un salto rápido sobre un palé en tu radio de terror, el Ente romperá el palé tras finalizar el salto y se desactivará Disolución.", "es": "Disolución", "charEn": "The Dredge", "charFr": "Le Dragage", "charEs": "La Draga"},{"id": "darknessRevelated", "name": "Darkness Revealed", "side": "killer", "img": "data:image/png;base64,", "desc": "En votre présence, les endroits jadis considérés sûrs sont peut-être les plus dangereux. Lorsque vous fouillez un casier, l'aura de tous les survivants dans un rayon de 30 mètres autour de chaque casier vous est révélée pendant 8 secondes. Cette compétence se recharge en 5 secondes.", "fr": "Ténèbres révélées", "descEn": "In your presence, places once thought to be safe are perhaps the most dangerous. When you search a locker, the auras of all Survivors within 30 meters of any lockers are revealed to you for 8 seconds. This perk has a 5-second cooldown.", "descEs": "En tu presencia, los lugares que parecían seguros ahora son los más peligrosos. Al inspeccionar una taquilla, se muestran las auras de todos los supervivientes que se encuentren a 30 metros de taquillas durante 8 segundos. Esta habilidad tiene un tiempo de recarga de 5 segundos.", "es": "Oscuridad expuesta", "charEn": "The Dredge", "charFr": "Le Dragage", "charEs": "La Draga"},{"id": "septicTouch", "name": "Septic Touch", "side": "killer", "img": "data:image/png;base64,", "desc": "Le Pays des ombres consume tout. Soigner ne fait que retarder l'inévitable. Quand un survivant effectue l'action de soins dans votre rayon de terreur, ce survivant subit Aveuglement et Épuisement. Ces effets perdurent 8 secondes après l'interruption par n'importe quel moyen d'une action de soins.", "fr": "Toucher septique", "descEn": "The Land of Shadows subsumes all. Healing only delays the inevitable. Whenever a Survivor performs the healing action within your Terror Radius, that Survivor suffers from Blindness and Exhausted. These effects linger for 8 seconds after a healing action is interrupted by any means.", "descEs": "La Tierra de las Sombras todo lo devora. La curación solo retrasa lo inevitable. Cuando un superviviente completa una acción de curación en tu radio de terror, el superviviente sufre Ceguera y Agotamiento. Estos efectos duran 8 segundos si se interrumpe una acción de curación del modo que sea.", "es": "Toque séptico", "charEn": "The Dredge", "charFr": "Le Dragage", "charEs": "La Draga"},{"id": "scaredToDeath", "name": "Hex: Scared to Death", "side": "killer", "img": "data:image/png;base64,", "desc": "Apres avoir accroche 3 survivants differents, un sort s'active sur un totem aleatoire. En chasse, casser une palette (attaque de base) fait crier les survivants a 13 metres et leur inflige 13% de Ralentissement pendant 3 secondes. Le sort persiste jusqu'a ce que le totem soit purifie ou beni.", "fr": "Hex : Mort de peur", "descEn": "After you hook 3 different Survivors, a Hex ignites on a random Totem. While chasing, basic-breaking a pallet makes Survivors within 13 metres scream and suffer 13% Hindered for 3 seconds. The Hex lasts until its Totem is cleansed or blessed.", "descEs": "Tras colgar a 3 supervivientes distintos, se enciende un maleficio en un totem aleatorio. Durante una persecucion, romper un pale (ataque basico) hace gritar a los supervivientes a 13 metros y les inflige un 13% de Ralentizacion durante 3 segundos. Dura hasta que el totem se purifique o bendiga.", "es": "Maleficio: Muerto de miedo", "charEn": "The Slasher", "charFr": "Le Slasher", "charEs": "El Asesino"},{"id": "silentShadow", "name": "Silent Shadow", "side": "killer", "img": "data:image/png;base64,", "desc": "Au debut de l'essai, tu beneficies du statut Indetectable pendant 13 secondes. Une fois les portes de sortie alimentees, tu deviens Indetectable pour le reste de l'essai.", "fr": "Ombre silencieuse", "descEn": "At the start of the Trial, you gain the Undetectable status effect for 13 seconds. Once the Exit Gates are powered, you become Undetectable for the rest of the Trial.", "descEs": "Al inicio de la prueba, obtienes el estado Indetectable durante 13 segundos. Cuando se activan las puertas de salida, te vuelves Indetectable durante el resto de la prueba.", "es": "Sombra silenciosa", "charEn": "The Slasher", "charFr": "Le Slasher", "charEs": "El Asesino"},{"id": "rampage", "name": "Rampage", "side": "killer", "img": "data:image/png;base64,", "desc": "Chaque fois que tu casses une palette ou un mur destructible (attaque de base), gagne un jeton (max 13). Lorsque tu es aveugle ou etourdi par une palette, gagne 1% de Hate par jeton pendant 13 secondes. Recharge : 20 secondes.", "fr": "Saccage", "descEn": "Each time you basic-break a pallet or breakable wall, gain a Token (up to 13). When blinded or pallet-stunned, gain 1% Haste per Token for 13 seconds. Cooldown: 20 seconds.", "descEs": "Cada vez que rompes un pale o muro destructible (ataque basico), ganas una carga (max. 13). Cuando te ciegan o aturden con un pale, ganas un 1% de Prisa por carga durante 13 segundos. Enfriamiento: 20 segundos.", "es": "Embestida", "charEn": "The Slasher", "charFr": "Le Slasher", "charEs": "El Asesino"},{"id": "aNursesCalling", "name": "A Nurse's Calling", "side": "killer", "img": "data:image/png;base64,", "desc": "Révèle l'aura des survivants qui se soignent autour de toi.", "fr": "L'Appel de l'infirmière", "descEn": "Reveals the auras of survivors healing around you.", "descEs": "Revela el aura de los supervivientes que se curan cerca de ti.", "es": "La llamada de la enfermera"}, {"id": "agitation", "name": "Agitation", "side": "killer", "img": "data:image/png;base64,", "desc": "Te déplaces plus vite en portant un survivant et augmente ton rayon de terreur.", "fr": "Agitation", "descEn": "Move faster while carrying a survivor; increases your terror radius.", "descEs": "Te mueves más rápido cargando a un superviviente; aumenta tu radio del terror.", "es": "Agitación"}, {"id": "alienInstinct", "name": "Alien Instinct", "side": "killer", "img": "data:image/png;base64,", "desc": "Après une accroche : révèle le survivant le plus loin et le rend Exposé un court instant.", "fr": "Instinct extraterrestre", "descEn": "After a hook: reveals the farthest survivor and makes them Exposed briefly.", "descEs": "Tras un gancho: revela al superviviente más lejano y lo deja Expuesto un instante.", "es": "Instinto alienígena"}, {"id": "awakenedAwareness", "name": "Awakened Awareness", "side": "killer", "img": "data:image/png;base64,", "desc": "En portant un survivant, tu vois l'aura des autres autour de toi.", "fr": "Conscience éveillée", "descEn": "While carrying a survivor, you see the auras of others around you.", "descEs": "Cargando a un superviviente, ves el aura de los demás a tu alrededor.", "es": "Conciencia despierta"}, {"id": "bamboozle", "name": "Bamboozle", "side": "killer", "img": "data:image/png;base64,", "desc": "Tu sautes les fenêtres plus vite et les bloques après ton passage.", "fr": "Entourloupe", "descEn": "Vault windows faster and block them after you use them.", "descEs": "Saltas ventanas más rápido y las bloqueas tras usarlas.", "es": "Engaño"}, {"id": "barbecueAndChilli", "name": "Barbecue & Chilli", "side": "killer", "img": "data:image/png;base64,", "desc": "Après une accroche : révèle l'aura des survivants éloignés.", "fr": "Barbecue & Chili", "descEn": "After a hook: reveals the auras of distant survivors.", "descEs": "Tras un gancho: revela el aura de los supervivientes lejanos.", "es": "Barbacoa y chili"}, {"id": "bitterMurmur", "name": "Bitter Murmur", "side": "killer", "img": "data:image/png;base64,", "desc": "Révèle les survivants proches d'un générateur réparé, et plus largement à la fin.", "fr": "Murmure amer", "descEn": "Reveals survivors near a completed generator, and more broadly at the end.", "descEs": "Revela a los supervivientes cerca de un generador reparado, y más al final.", "es": "Murmullo amargo"}, {"id": "bloodWarden", "name": "Blood Warden", "side": "killer", "img": "data:image/png;base64,", "desc": "Quand une porte est ouverte, une accroche bloque les sorties un moment.", "fr": "Gardien de sang", "descEn": "Once a gate is open, hooking blocks the exits for a while.", "descEs": "Con una puerta abierta, colgar a alguien bloquea las salidas un tiempo.", "es": "Guardián de sangre"}, {"id": "bloodhound", "name": "Bloodhound", "side": "killer", "img": "data:image/png;base64,", "desc": "Les traces de sang sont plus visibles et durent plus longtemps.", "fr": "Limier", "descEn": "Blood trails are more visible and last longer.", "descEs": "Los rastros de sangre son más visibles y duran más.", "es": "Sabueso"}, {"id": "brutalStrength", "name": "Brutal Strength", "side": "killer", "img": "data:image/png;base64,", "desc": "Casse palettes, murs et générateurs plus vite.", "fr": "Force brutale", "descEn": "Break pallets, walls and generators faster.", "descEs": "Rompe paletas, muros y generadores más rápido.", "es": "Fuerza brutal"}, {"id": "callOfBrine", "name": "Call of Brine", "side": "killer", "img": "data:image/png;base64,", "desc": "Un générateur frappé régresse plus vite et t'alerte sur ses skill checks.", "fr": "Appel des flots", "descEn": "A kicked generator regresses faster and alerts you on its skill checks.", "descEs": "Un generador pateado retrocede más rápido y te avisa de sus pruebas.", "es": "Llamada de la salmuera"}, {"id": "corruptIntervention", "name": "Corrupt Intervention", "side": "killer", "img": "data:image/png;base64,", "desc": "En début de partie : bloque les générateurs les plus éloignés un moment.", "fr": "Intervention corrompue", "descEn": "At the start: blocks the farthest generators for a while.", "descEs": "Al inicio: bloquea los generadores más lejanos un tiempo.", "es": "Intervención corrupta"}, {"id": "coupDeGrace", "name": "Coup de Grâce", "side": "killer", "img": "data:image/png;base64,", "desc": "Allonge fortement la portée de ton coup (système de jetons).", "fr": "Coup de grâce", "descEn": "Greatly extends your lunge range (token system).", "descEs": "Amplía mucho el alcance de tu ataque (sistema de fichas).", "es": "Golpe de gracia"}, {"id": "deadMansSwitch", "name": "Dead Man's Switch", "side": "killer", "img": "data:image/png;base64,", "desc": "Accrocher quelqu'un bloque les générateurs récemment lâchés.", "fr": "Interrupteur fatal", "descEn": "Hooking someone blocks recently released generators.", "descEs": "Colgar a alguien bloquea los generadores soltados recientemente.", "es": "Interruptor del muerto"}, {"id": "deadlock", "name": "Deadlock", "side": "killer", "img": "data:image/png;base64,", "desc": "Quand un générateur est fini : bloque celui le plus avancé un moment.", "fr": "Impasse", "descEn": "When a generator is completed: blocks the most-progressed one for a while.", "descEs": "Cuando se completa un generador: bloquea el más avanzado un tiempo.", "es": "Punto muerto"}, {"id": "deerstalker", "name": "Deerstalker", "side": "killer", "img": "data:image/png;base64,", "desc": "Révèle l'aura des survivants à terre.", "fr": "Traque", "descEn": "Reveals the auras of downed survivors.", "descEs": "Revela el aura de los supervivientes en el suelo.", "es": "Acecho"}, {"id": "discordance", "name": "Discordance", "side": "killer", "img": "data:image/png;base64,", "desc": "Te signale les générateurs réparés par plusieurs survivants à la fois.", "fr": "Discordance", "descEn": "Flags generators being repaired by multiple survivors at once.", "descEs": "Marca los generadores reparados por varios supervivientes a la vez.", "es": "Discordancia"}, {"id": "distressing", "name": "Distressing", "side": "killer", "img": "data:image/png;base64,", "desc": "Augmente ton rayon de terreur et le gain de points en chasse.", "fr": "Angoisse", "descEn": "Increases your terror radius and chase point gains.", "descEs": "Aumenta tu radio del terror y los puntos en persecución.", "es": "Angustia"}, {"id": "enduring", "name": "Enduring", "side": "killer", "img": "data:image/png;base64,", "desc": "Réduit fortement la durée des étourdissements de palette.", "fr": "Endurant", "descEn": "Greatly reduces pallet stun duration.", "descEs": "Reduce mucho la duración de los aturdimientos por paleta.", "es": "Resistente"}, {"id": "eruption", "name": "Eruption", "side": "killer", "img": "data:image/png;base64,", "desc": "Frapper un générateur le bloque ; mettre un survivant à terre le fait exploser et crier les autres dessus.", "fr": "Éruption", "descEn": "Kicking a generator primes it; downing a survivor explodes it and screams survivors on it.", "descEs": "Patear un generador lo prepara; derribar a alguien lo hace explotar y gritar a quien lo repare.", "es": "Erupción"}, {"id": "franklinsDemise", "name": "Franklin's Demise", "side": "killer", "img": "data:image/png;base64,", "desc": "Tes coups font lâcher l'objet du survivant, qui se vide avec le temps.", "fr": "Perte de Franklin", "descEn": "Your hits make survivors drop their item, which drains over time.", "descEs": "Tus golpes hacen soltar el objeto, que se vacía con el tiempo.", "es": "Perdición de Franklin"}, {"id": "grimEmbrace", "name": "Grim Embrace", "side": "killer", "img": "data:image/png;base64,", "desc": "Accrocher chaque survivant bloque peu à peu les générateurs et révèle l'Obsession.", "fr": "Étreinte funeste", "descEn": "Hooking each survivor progressively blocks generators and reveals the Obsession.", "descEs": "Colgar a cada superviviente bloquea generadores poco a poco y revela a la Obsesión.", "es": "Abrazo sombrío"}, {"id": "devourHope", "name": "Hex: Devour Hope", "side": "killer", "img": "data:image/png;base64,", "desc": "Hex : accroche loin du totem pour rendre les survivants Exposés et les tuer à la main.", "fr": "Maléfice : Dévorer l'espoir", "descEn": "Hex: hook far from the totem to make survivors Exposed and kill them by hand.", "descEs": "Hechizo: cuelga lejos del tótem para Exponer a los supervivientes y matarlos a mano.", "es": "Hechizo: Devorar esperanza"}, {"id": "hauntedGround", "name": "Hex: Haunted Ground", "side": "killer", "img": "data:image/png;base64,", "desc": "Hex : deux totems pièges ; en purifier un rend tous les survivants Exposés un moment.", "fr": "Maléfice : Terre hantée", "descEn": "Hex: two trap totems; cleansing one makes all survivors Exposed for a while.", "descEs": "Hechizo: dos tótems trampa; purificar uno Expone a todos un tiempo.", "es": "Hechizo: Tierra encantada"}, {"id": "noOneEscapesDeath", "name": "Hex: No One Escapes Death", "side": "killer", "img": "data:image/png;base64,", "desc": "Hex : à la fin, tant qu'un totem brille, les survivants sont Exposés.", "fr": "Maléfice : Nul n'échappe à la mort", "descEn": "Hex: in endgame, while a totem stands, survivors are Exposed.", "descEs": "Hechizo: al final, mientras un tótem siga en pie, los supervivientes están Expuestos.", "es": "Hechizo: Nadie escapa de la muerte"}, {"id": "pentimento", "name": "Hex: Pentimento", "side": "killer", "img": "data:image/png;base64,", "desc": "Hex : rallume les totems nettoyés pour infliger des malus aux survivants.", "fr": "Maléfice : Pentimento", "descEn": "Hex: relight cleansed totems to inflict penalties on survivors.", "descEs": "Hechizo: reaviva los tótems purificados para penalizar a los supervivientes.", "es": "Hechizo: Pentimento"}, {"id": "plaything", "name": "Hex: Plaything", "side": "killer", "img": "data:image/png;base64,", "desc": "Hex : après une accroche, la victime est Maudite et ne voit pas son totem au début.", "fr": "Maléfice : Jouet", "descEn": "Hex: after a hook, the victim is Cursed and can't see their totem at first.", "descEs": "Hechizo: tras un gancho, la víctima queda Maldita y no ve su tótem al principio.", "es": "Hechizo: Juguete"}, {"id": "ruin", "name": "Hex: Ruin", "side": "killer", "img": "data:image/png;base64,", "desc": "Hex : les générateurs non touchés régressent seuls tant que le totem brille.", "fr": "Maléfice : Ruine", "descEn": "Hex: untouched generators regress on their own while the totem stands.", "descEs": "Hechizo: los generadores sin tocar retroceden solos mientras el tótem siga en pie.", "es": "Hechizo: Ruina"}, {"id": "hubris", "name": "Hubris", "side": "killer", "img": "data:image/png;base64,", "desc": "Quand un survivant t'étourdit, il devient Exposé un court instant.", "fr": "Hubris", "descEn": "When a survivor stuns you, they become Exposed briefly.", "descEs": "Cuando un superviviente te aturde, queda Expuesto un instante.", "es": "Soberbia"}, {"id": "insidious", "name": "Insidious", "side": "killer", "img": "data:image/png;base64,", "desc": "Rester immobile te rend progressivement indétectable.", "fr": "Insidieux", "descEn": "Standing still gradually makes you Undetectable.", "descEs": "Quedarte quieto te vuelve Indetectable poco a poco.", "es": "Insidioso"}, {"id": "ironGrasp", "name": "Iron Grasp", "side": "killer", "img": "data:image/png;base64,", "desc": "Les survivants portés se débattent moins et plus lentement.", "fr": "Poigne de fer", "descEn": "Carried survivors wiggle less and more slowly.", "descEs": "Los supervivientes cargados forcejean menos y más despacio.", "es": "Agarre de hierro"}, {"id": "jolt", "name": "Jolt", "side": "killer", "img": "data:image/png;base64,", "desc": "Mettre un survivant à terre fait régresser et exploser les générateurs proches.", "fr": "Secousse", "descEn": "Downing a survivor regresses and damages nearby generators.", "descEs": "Derribar a un superviviente retrocede y daña los generadores cercanos.", "es": "Sacudida"}, {"id": "lethalPursuer", "name": "Lethal Pursuer", "side": "killer", "img": "data:image/png;base64,", "desc": "Début de partie : révèle tous les survivants ; prolonge tes lectures d'aura.", "fr": "Poursuivant mortel", "descEn": "Match start: reveals all survivors; extends your aura reads.", "descEs": "Inicio de partida: revela a todos los supervivientes; alarga tus lecturas de aura.", "es": "Perseguidor letal"}, {"id": "lightborn", "name": "Lightborn", "side": "killer", "img": "data:image/png;base64,", "desc": "Tu ne peux plus être aveuglé par les lampes et tu vois qui a essayé.", "fr": "Né de la lumière", "descEn": "You can't be blinded by flashlights and you see who tried.", "descEs": "No puedes ser cegado por linternas y ves quién lo intentó.", "es": "Hijo de la luz"}, {"id": "makeYourChoice", "name": "Make Your Choice", "side": "killer", "img": "data:image/png;base64,", "desc": "Quand un survivant en décroche un autre loin de toi, il devient Exposé.", "fr": "Fais ton choix", "descEn": "When a survivor unhooks another far from you, they become Exposed.", "descEs": "Cuando un superviviente descuelga a otro lejos de ti, queda Expuesto.", "es": "Toma tu decisión"}, {"id": "monstrousShrine", "name": "Monstrous Shrine", "side": "killer", "img": "data:image/png;base64,", "desc": "Renforce tes crochets du sous-sol (sacrifice plus rapide).", "fr": "Sanctuaire monstrueux", "descEn": "Strengthens your basement hooks (faster sacrifice).", "descEs": "Refuerza tus ganchos del sótano (sacrificio más rápido).", "es": "Santuario monstruoso"}, {"id": "nemesis", "name": "Nemesis", "side": "killer", "img": "data:image/png;base64,", "desc": "T'étourdir/t'aveugler désigne une nouvelle Obsession, qui devient Exposée.", "fr": "Némésis", "descEn": "Stunning/blinding you marks a new Obsession, who becomes Exposed.", "descEs": "Aturdirte/cegarte marca a una nueva Obsesión, que queda Expuesta.", "es": "Némesis"}, {"id": "nowhereToHide", "name": "Nowhere to Hide", "side": "killer", "img": "data:image/png;base64,", "desc": "Casser un générateur révèle les survivants proches.", "fr": "Nulle part où se cacher", "descEn": "Kicking a generator reveals nearby survivors.", "descEs": "Patear un generador revela a los supervivientes cercanos.", "es": "Ningún lugar donde esconderse"}, {"id": "overcharge", "name": "Overcharge", "side": "killer", "img": "data:image/png;base64,", "desc": "Un générateur frappé régresse vite et devient difficile à réparer.", "fr": "Surcharge", "descEn": "A kicked generator regresses fast and becomes hard to repair.", "descEs": "Un generador pateado retrocede rápido y se vuelve difícil de reparar.", "es": "Sobrecarga"}, {"id": "popGoesTheWeasel", "name": "Pop Goes the Weasel", "side": "killer", "img": "data:image/png;base64,", "desc": "Après une accroche : ton prochain coup de pied retire une grosse part de réparation.", "fr": "Et pop !", "descEn": "After a hook: your next kick removes a large chunk of repair progress.", "descEs": "Tras un gancho: tu próxima patada quita una gran parte de la reparación.", "es": "¡Pum, va la comadreja!"}, {"id": "predator", "name": "Predator", "side": "killer", "img": "data:image/png;base64,", "desc": "Les traces de griffes sont regroupées et plus faciles à suivre.", "fr": "Prédateur", "descEn": "Scratch marks are tighter together and easier to follow.", "descEs": "Las marcas de arañazo están más juntas y son más fáciles de seguir.", "es": "Depredador"}, {"id": "rancor", "name": "Rancor", "side": "killer", "img": "data:image/png;base64,", "desc": "Révèle peu à peu l'Obsession ; à la fin tu peux la tuer à la main.", "fr": "Rancœur", "descEn": "Gradually reveals the Obsession; at the end you can kill them by hand.", "descEs": "Revela poco a poco a la Obsesión; al final puedes matarla a mano.", "es": "Rencor"}, {"id": "saveTheBestForLast", "name": "Save the Best for Last", "side": "killer", "img": "data:image/png;base64,", "desc": "Frapper des non-Obsession réduit ton temps de récupération de coup (jetons).", "fr": "Garder le meilleur pour la fin", "descEn": "Hitting non-Obsession survivors reduces your hit cooldown (tokens).", "descEs": "Golpear a no-Obsesión reduce tu recuperación de golpe (fichas).", "es": "Guarda lo mejor para el final"}, {"id": "painResonance", "name": "Scourge Hook: Pain Resonance", "side": "killer", "img": "data:image/png;base64,", "desc": "Crochet à fléau : une accroche dessus fait régresser et crier le générateur le plus avancé.", "fr": "Crochet à fléau : Résonance de douleur", "descEn": "Scourge hook: hooking on one regresses and screams the most-progressed generator.", "descEs": "Gancho del azote: colgar en uno retrocede y hace gritar el generador más avanzado.", "es": "Gancho del azote: Resonancia del dolor"}, {"id": "shadowborn", "name": "Shadowborn", "side": "killer", "img": "data:image/png;base64,", "desc": "Élargit ton champ de vision.", "fr": "Né de l'ombre", "descEn": "Widens your field of view.", "descEs": "Amplía tu campo de visión.", "es": "Hijo de la sombra"}, {"id": "sloppyButcher", "name": "Sloppy Butcher", "side": "killer", "img": "data:image/png;base64,", "desc": "Tes coups font plus saigner et ralentissent le soin des blessés.", "fr": "Boucher négligent", "descEn": "Your hits cause heavier bleeding and slow injured survivors' healing.", "descEs": "Tus golpes provocan más hemorragia y ralentizan la curación de los heridos.", "es": "Carnicero chapucero"}, {"id": "spiesFromTheShadows", "name": "Spies from the Shadows", "side": "killer", "img": "data:image/png;base64,", "desc": "Les corbeaux dérangés par les survivants t'indiquent leur position.", "fr": "Espions de l'ombre", "descEn": "Crows disturbed by survivors reveal their location to you.", "descEs": "Los cuervos molestados por los supervivientes te indican su posición.", "es": "Espías de las sombras"}, {"id": "spiritFury", "name": "Spirit Fury", "side": "killer", "img": "data:image/png;base64,", "desc": "Après quelques palettes encaissées, la prochaine palette baissée se casse seule.", "fr": "Furie de l'esprit", "descEn": "After taking a few pallet stuns, the next dropped pallet breaks on its own.", "descEs": "Tras encajar varias paletas, la siguiente paleta tirada se rompe sola.", "es": "Furia del espíritu"}, {"id": "stridor", "name": "Stridor", "side": "killer", "img": "data:image/png;base64,", "desc": "Tu entends bien plus fort les respirations et gémissements des survivants.", "fr": "Stridor", "descEn": "You hear survivors' breathing and grunts much louder.", "descEs": "Oyes mucho más fuerte la respiración y gemidos de los supervivientes.", "es": "Estridor"}, {"id": "thatanophobia", "name": "Thanatophobia", "side": "killer", "img": "data:image/png;base64,", "desc": "Chaque survivant blessé/à terre/accroché ralentit toutes leurs actions.", "fr": "Thanatophobie", "descEn": "Each injured/downed/hooked survivor slows all survivors' actions.", "descEs": "Cada superviviente herido/en el suelo/colgado ralentiza todas sus acciones.", "es": "Tanatofobia"}, {"id": "thrillingTremors", "name": "Thrilling Tremors", "side": "killer", "img": "data:image/png;base64,", "desc": "Accrocher un survivant bloque tous les générateurs non réparés un moment.", "fr": "Frissons palpitants", "descEn": "Hooking a survivor blocks all un-repaired generators for a while.", "descEs": "Colgar a un superviviente bloquea todos los generadores sin reparar un tiempo.", "es": "Temblores emocionantes"}, {"id": "tinkerer", "name": "Tinkerer", "side": "killer", "img": "data:image/png;base64,", "desc": "Quand un générateur est presque fini : alerte + indétectable un court instant.", "fr": "Bricoleur", "descEn": "When a generator is nearly done: alert + Undetectable briefly.", "descEs": "Cuando un generador casi está listo: alerta + Indetectable un instante.", "es": "Manitas"}, {"id": "ultimateWeapon", "name": "Ultimate Weapon", "side": "killer", "img": "data:image/png;base64,", "desc": "Ouvrir un casier fait crier et rend Aveugles les survivants autour.", "fr": "Arme ultime", "descEn": "Opening a locker screams and Blinds survivors in an area.", "descEs": "Abrir una taquilla hace gritar y Ciega a los supervivientes alrededor.", "es": "Arma definitiva"}, {"id": "unnervingPresence", "name": "Unnerving Presence", "side": "killer", "img": "data:image/png;base64,", "desc": "Réduit et complique les skill checks des survivants dans ton rayon de terreur.", "fr": "Présence troublante", "descEn": "Shrinks and worsens survivors' skill checks within your terror radius.", "descEs": "Reduce y complica las pruebas de habilidad en tu radio del terror.", "es": "Presencia inquietante"}, {"id": "unrelenting", "name": "Unrelenting", "side": "killer", "img": "data:image/png;base64,", "desc": "Réduit le temps de récupération après un coup manqué.", "fr": "Implacable", "descEn": "Reduces the cooldown after a missed attack.", "descEs": "Reduce la recuperación tras un ataque fallado.", "es": "Implacable"}, {"id": "whispers", "name": "Whispers", "side": "killer", "img": "data:image/png;base64,", "desc": "T'indique quand un survivant se trouve à moins de 32 m de toi.", "fr": "Murmures", "descEn": "Tells you when a survivor is within 32 m of you.", "descEs": "Te indica cuando un superviviente está a menos de 32 m.", "es": "Susurros"}, {"id": "adrenaline", "name": "Adrenaline", "side": "survivor", "img": "data:image/png;base64,", "desc": "Quand la dernière porte est alimentée : te soigne d'un état de santé et donne un sprint instantané.", "fr": "Adrénaline", "descEn": "When the last gate is powered: heals you one health state and grants an instant sprint.", "descEs": "Cuando se alimenta la última puerta: te cura un estado de salud y te da un sprint instantáneo.", "es": "Adrenalina"}, {"id": "aftercare", "name": "Aftercare", "side": "survivor", "img": "data:image/png;base64,", "desc": "Tu vois l'aura des survivants que tu soignes ou décroches, et eux la tienne.", "fr": "Postcure", "descEn": "You see the auras of survivors you heal or unhook, and they see yours.", "descEs": "Ves el aura de los supervivientes que curas o descuelgas, y ellos la tuya.", "es": "Cuidados posteriores"}, {"id": "anyMeansNecessary", "name": "Any Means Necessary", "side": "survivor", "img": "data:image/png;base64,", "desc": "Permet de relever les palettes déjà tombées.", "fr": "Tous les moyens sont bons", "descEn": "Lets you reset dropped pallets.", "descEs": "Permite levantar las paletas ya tiradas.", "es": "Por todos los medios"}, {"id": "backgroundPlayer", "name": "Background Player", "side": "survivor", "img": "data:image/png;base64,", "desc": "Quand le tueur porte un survivant, tu cours bien plus vite pendant quelques secondes.", "fr": "Soutien de l'ombre", "descEn": "While the killer carries a survivor, you run much faster for a few seconds.", "descEs": "Mientras el asesino carga a un superviviente, corres mucho más rápido unos segundos.", "es": "Jugador de fondo"}, {"id": "balancedLanding", "name": "Balanced Landing", "side": "survivor", "img": "data:image/png;base64,", "desc": "Supprime le bruit de chute et donne un sprint à l'atterrissage (te rend Épuisé).", "fr": "Atterrissage maîtrisé", "descEn": "Removes landing noise and grants a sprint on landing (causes Exhausted).", "descEs": "Elimina el ruido de caída y da un sprint al aterrizar (causa Agotado).", "es": "Aterrizaje equilibrado"}, {"id": "bond", "name": "Bond", "side": "survivor", "img": "data:image/png;base64,", "desc": "Tu vois l'aura des autres survivants proches de toi.", "fr": "Lien", "descEn": "You see the auras of other survivors near you.", "descEs": "Ves el aura de otros supervivientes cercanos.", "es": "Vínculo"}, {"id": "boonCircleOfHealing", "name": "Boon: Circle of Healing", "side": "survivor", "img": "data:image/png;base64,", "desc": "Bénédiction : les survivants dans la zone se soignent plus vite.", "fr": "Bénédiction : Cercle de guérison", "descEn": "Boon: survivors inside the radius heal faster.", "descEs": "Bendición: los supervivientes dentro del radio se curan más rápido.", "es": "Bendición: Círculo de curación"}, {"id": "boonShadowStep", "name": "Boon: Shadow Step", "side": "survivor", "img": "data:image/png;base64,", "desc": "Bénédiction : cache ton aura et tes traces de pas dans la zone.", "fr": "Bénédiction : Pas de l'ombre", "descEn": "Boon: hides your aura and scratch marks within the radius.", "descEs": "Bendición: oculta tu aura y tus marcas dentro del radio.", "es": "Bendición: Paso sombrío"}, {"id": "borrowedTime", "name": "Borrowed Time", "side": "survivor", "img": "data:image/png;base64,", "desc": "Le survivant que tu décroches reçoit Persévérance et encaisse un coup quelques secondes.", "fr": "Temps emprunté", "descEn": "The survivor you unhook gets Endurance and can take a hit for a few seconds.", "descEs": "El superviviente que descuelgas obtiene Resistencia y aguanta un golpe unos segundos.", "es": "Tiempo prestado"}, {"id": "botanyKnowledge", "name": "Botany Knowledge", "side": "survivor", "img": "data:image/png;base64,", "desc": "Augmente la vitesse de soin et l'efficacité des trousses.", "fr": "Connaissances botaniques", "descEn": "Increases healing speed and med-kit efficiency.", "descEs": "Aumenta la velocidad de curación y la eficacia de los botiquines.", "es": "Conocimientos de botánica"}, {"id": "buckleUp", "name": "Buckle Up", "side": "survivor", "img": "data:image/png;base64,", "desc": "En relevant un survivant à terre, tu vois l'aura du tueur ; vous gagnez tous deux Persévérance.", "fr": "Accroche-toi", "descEn": "Recovering a downed survivor reveals the killer's aura; you both gain Endurance.", "descEs": "Al levantar a un superviviente, ves el aura del asesino; ambos ganáis Resistencia.", "es": "Prepárate"}, {"id": "calmSpirit", "name": "Calm Spirit", "side": "survivor", "img": "data:image/png;base64,", "desc": "Tu ne cries plus (corbeaux, perks de cri) et ne révèles pas ta position.", "fr": "Esprit serein", "descEn": "You no longer scream (crows, scream perks) and don't reveal your position.", "descEs": "Ya no gritas (cuervos, perks de grito) y no revelas tu posición.", "es": "Espíritu calmado"}, {"id": "darkSense", "name": "Dark Sense", "side": "survivor", "img": "data:image/png;base64,", "desc": "Quand un générateur est réparé, tu vois l'aura du tueur quelques secondes.", "fr": "Perception", "descEn": "When a generator is completed, you see the killer's aura for a few seconds.", "descEs": "Cuando se repara un generador, ves el aura del asesino unos segundos.", "es": "Sentido oscuro"}, {"id": "deadHard", "name": "Dead Hard", "side": "survivor", "img": "data:image/png;base64,", "desc": "Une fois blessé : appuie au bon moment pour esquiver un coup (te rend Épuisé).", "fr": "Acharné", "descEn": "While injured: press at the right moment to dodge a hit (causes Exhausted).", "descEs": "Estando herido: pulsa en el momento justo para esquivar un golpe (causa Agotado).", "es": "Hasta la muerte"}, {"id": "decisiveStrike", "name": "Decisive Strike", "side": "survivor", "img": "data:image/png;base64,", "desc": "Après un décrochage, étourdis le tueur s'il te reprend trop vite.", "fr": "Frappe décisive", "descEn": "After being unhooked, stun the killer if they grab you too soon.", "descEs": "Tras ser descolgado, aturdes al asesino si te agarra demasiado pronto.", "es": "Golpe decisivo"}, {"id": "detectivesHunch", "name": "Detective's Hunch", "side": "survivor", "img": "data:image/png;base64,", "desc": "Révèle l'aura des générateurs, coffres et totems autour des générateurs réparés.", "fr": "Flair du détective", "descEn": "Reveals the auras of generators, chests and totems around completed generators.", "descEs": "Revela el aura de generadores, cofres y tótems alrededor de los generadores reparados.", "es": "Corazonada del detective"}, {"id": "distortion", "name": "Distortion", "side": "survivor", "img": "data:image/png;base64,", "desc": "Cache ton aura quand le tueur tente de la lire (système de jetons).", "fr": "Distorsion", "descEn": "Hides your aura when the killer tries to read it (token system).", "descEs": "Oculta tu aura cuando el asesino intenta leerla (sistema de fichas).", "es": "Distorsión"}, {"id": "dramaturgy", "name": "Dramaturgy", "side": "survivor", "img": "data:image/png;base64,", "desc": "Sprint qui déclenche un effet aléatoire (objet, esquive…) et te rend Épuisé.", "fr": "Dramaturgie", "descEn": "A sprint that triggers a random effect (item, dodge...) and causes Exhausted.", "descEs": "Un sprint que activa un efecto aleatorio (objeto, esquiva...) y causa Agotado.", "es": "Dramaturgia"}, {"id": "dejaVu", "name": "Déjà Vu", "side": "survivor", "img": "data:image/png;base64,", "desc": "Révèle en permanence les 3 générateurs les plus proches et donne un bonus de réparation dessus.", "fr": "Déjà-vu", "descEn": "Permanently reveals the 3 nearest generators and grants a repair bonus on them.", "descEs": "Revela permanentemente los 3 generadores más cercanos y da un bono de reparación en ellos.", "es": "Déjà vu"}, {"id": "empathy", "name": "Empathy", "side": "survivor", "img": "data:image/png;base64,", "desc": "Tu vois l'aura des survivants blessés ou à terre.", "fr": "Empathie", "descEn": "You see the auras of injured or downed survivors.", "descEs": "Ves el aura de los supervivientes heridos o en el suelo.", "es": "Empatía"}, {"id": "flashbang", "name": "Flashbang", "side": "survivor", "img": "data:image/png;base64,", "desc": "Fabrique une grenade aveuglante en réparant des générateurs.", "fr": "Flashbang", "descEn": "Craft a blinding grenade by repairing generators.", "descEs": "Fabrica una granada cegadora reparando generadores.", "es": "Granada cegadora"}, {"id": "forThePeople", "name": "For the People", "side": "survivor", "img": "data:image/png;base64,", "desc": "Soigne instantanément un survivant blessé en prenant son état de santé à sa place.", "fr": "Pour le peuple", "descEn": "Instantly heal an injured survivor by taking their health state instead.", "descEs": "Cura al instante a un superviviente herido tomando su estado de salud en su lugar.", "es": "Por el pueblo"}, {"id": "headOn", "name": "Head On", "side": "survivor", "img": "data:image/png;base64,", "desc": "Sortir d'un casier en courant étourdit le tueur proche.", "fr": "Tête la première", "descEn": "Bursting out of a locker stuns a nearby killer.", "descEs": "Salir corriendo de una taquilla aturde al asesino cercano.", "es": "De frente"}, {"id": "hope", "name": "Hope", "side": "survivor", "img": "data:image/png;base64,", "desc": "Quand toutes les portes sont alimentées : gros bonus de vitesse de course.", "fr": "Espoir", "descEn": "When all gates are powered: big movement-speed bonus.", "descEs": "Cuando todas las puertas están alimentadas: gran bono de velocidad.", "es": "Esperanza"}, {"id": "innerStrength", "name": "Inner Strength", "side": "survivor", "img": "data:image/png;base64,", "desc": "Purifier un totem te permet de te soigner entièrement en te cachant dans un casier.", "fr": "Force intérieure", "descEn": "Cleansing a totem lets you fully heal by hiding in a locker.", "descEs": "Purificar un tótem te permite curarte por completo escondiéndote en una taquilla.", "es": "Fuerza interior"}, {"id": "ironWill", "name": "Iron Will", "side": "survivor", "img": "data:image/png;base64,", "desc": "Réduit fortement (ou supprime) tes gémissements de douleur.", "fr": "Volonté de fer", "descEn": "Greatly reduces (or removes) your grunts of pain.", "descEs": "Reduce mucho (o elimina) tus gemidos de dolor.", "es": "Voluntad de hierro"}, {"id": "kindred", "name": "Kindred", "side": "survivor", "img": "data:image/png;base64,", "desc": "Pendant une accroche, tout le monde voit les auras des survivants (et du tueur s'il est proche).", "fr": "Parenté", "descEn": "While someone is hooked, everyone sees survivor auras (and the killer's if nearby).", "descEs": "Mientras alguien está en el gancho, todos ven las auras de los supervivientes (y la del asesino si está cerca).", "es": "Afinidad"}, {"id": "leader", "name": "Leader", "side": "survivor", "img": "data:image/png;base64,", "desc": "Booste la vitesse des actions coopératives des survivants autour de toi.", "fr": "Meneur", "descEn": "Boosts the speed of co-op actions for survivors around you.", "descEs": "Mejora la velocidad de las acciones cooperativas de los supervivientes cercanos.", "es": "Líder"}, {"id": "lightweight", "name": "Lightweight", "side": "survivor", "img": "data:image/png;base64,", "desc": "Tes traces disparaissent plus vite : tu es plus difficile à pister.", "fr": "Poids plume", "descEn": "Your scratch marks fade faster, making you harder to track.", "descEs": "Tus marcas desaparecen más rápido: eres más difícil de rastrear.", "es": "Ligero"}, {"id": "lithe", "name": "Lithe", "side": "survivor", "img": "data:image/png;base64,", "desc": "Sprint après un saut rapide de fenêtre ou de palette (te rend Épuisé).", "fr": "Souplesse", "descEn": "Sprint after a fast vault of a window or pallet (causes Exhausted).", "descEs": "Sprint tras saltar rápido una ventana o paleta (causa Agotado).", "es": "Agilidad"}, {"id": "luckyBreak", "name": "Lucky Break", "side": "survivor", "img": "data:image/png;base64,", "desc": "Une fois blessé : plus de traces de sang ni de gémissements pendant un temps limité.", "fr": "Répit", "descEn": "While injured: no blood trails or grunts for a limited time.", "descEs": "Estando herido: sin rastros de sangre ni gemidos durante un tiempo limitado.", "es": "Golpe de suerte"}, {"id": "madeForThis", "name": "Made for This", "side": "survivor", "img": "data:image/png;base64,", "desc": "Vitesse de course accrue quand tu es blessé, et bonus d'endurance en soignant.", "fr": "Fait pour ça", "descEn": "Increased running speed while injured, plus an Endurance bonus when healing.", "descEs": "Mayor velocidad de carrera estando herido, y bono de Resistencia al curar.", "es": "Hecho para esto"}, {"id": "noOneLeftBehind", "name": "No One Left Behind", "side": "survivor", "img": "data:image/png;base64,", "desc": "Portes alimentées : gros bonus pour décrocher et soigner les autres.", "fr": "On n'oublie personne", "descEn": "Gates powered: big bonus to unhook and heal others.", "descEs": "Puertas alimentadas: gran bono para descolgar y curar a otros.", "es": "Nadie se queda atrás"}, {"id": "offTheRecord", "name": "Off the Record", "side": "survivor", "img": "data:image/png;base64,", "desc": "Après un décrochage : ton aura est cachée et tu encaisses un coup en silence.", "fr": "Officieux", "descEn": "After being unhooked: your aura is hidden and you take a hit silently.", "descEs": "Tras ser descolgado: tu aura se oculta y aguantas un golpe en silencio.", "es": "Extraoficial"}, {"id": "openHanded", "name": "Open-Handed", "side": "survivor", "img": "data:image/png;base64,", "desc": "Augmente la portée de toutes les lectures d'aura alliées.", "fr": "Générosité", "descEn": "Increases the range of all allied aura-reading.", "descEs": "Aumenta el alcance de todas las lecturas de aura aliadas.", "es": "Mano abierta"}, {"id": "plunderersInstinct", "name": "Plunderer's Instinct", "side": "survivor", "img": "data:image/png;base64,", "desc": "Révèle l'aura des coffres et améliore les objets trouvés dedans.", "fr": "Instinct de pilleur", "descEn": "Reveals chest auras and improves the items found in them.", "descEs": "Revela el aura de los cofres y mejora los objetos encontrados.", "es": "Instinto de saqueador"}, {"id": "premonition", "name": "Premonition", "side": "survivor", "img": "data:image/png;base64,", "desc": "T'alerte quand tu regardes en direction du tueur proche.", "fr": "Prémonition", "descEn": "Warns you when you look toward a nearby killer.", "descEs": "Te avisa cuando miras hacia el asesino cercano.", "es": "Premonición"}, {"id": "proveThyself", "name": "Prove Thyself", "side": "survivor", "img": "data:image/png;base64,", "desc": "Booste la vitesse de réparation quand plusieurs survivants réparent ensemble.", "fr": "Prouve-toi", "descEn": "Boosts repair speed when several survivors repair together.", "descEs": "Mejora la velocidad de reparación cuando varios reparan juntos.", "es": "Demuéstrate"}, {"id": "quickAndQuiet", "name": "Quick & Quiet", "side": "survivor", "img": "data:image/png;base64,", "desc": "Supprime le bruit en sautant une fenêtre ou en entrant dans un casier.", "fr": "Rapide et silencieux", "descEn": "Silences your window vaults and locker entries.", "descEs": "Silencia tus saltos de ventana y entradas a taquillas.", "es": "Rápido y silencioso"}, {"id": "reassurance", "name": "Reassurance", "side": "survivor", "img": "data:image/png;base64,", "desc": "Près d'un survivant accroché : met en pause sa barre de sacrifice.", "fr": "Réconfort", "descEn": "Near a hooked survivor: pauses their sacrifice progress.", "descEs": "Cerca de un superviviente en el gancho: pausa su barra de sacrificio.", "es": "Tranquilidad"}, {"id": "resilience", "name": "Resilience", "side": "survivor", "img": "data:image/png;base64,", "desc": "Toutes tes actions sont plus rapides quand tu es blessé.", "fr": "Résilience", "descEn": "All your actions are faster while you're injured.", "descEs": "Todas tus acciones son más rápidas estando herido.", "es": "Resiliencia"}, {"id": "saboteur", "name": "Saboteur", "side": "survivor", "img": "data:image/png;base64,", "desc": "Sabote les crochets à mains nues et voit leur aura quand un survivant est porté.", "fr": "Saboteur", "descEn": "Sabotage hooks bare-handed and see their auras while a survivor is carried.", "descEs": "Sabotea ganchos a mano y ve su aura cuando cargan a un superviviente.", "es": "Saboteador"}, {"id": "selfCare", "name": "Self-Care", "side": "survivor", "img": "data:image/png;base64,", "desc": "Te soigner seul, sans trousse (plus lentement).", "fr": "Autosoin", "descEn": "Heal yourself without a med-kit (more slowly).", "descEs": "Cúrate solo sin botiquín (más despacio).", "es": "Autocuidado"}, {"id": "slipperyMeat", "name": "Slippery Meat", "side": "survivor", "img": "data:image/png;base64,", "desc": "Plus de chances de t'échapper d'un crochet ou d'un piège à ours.", "fr": "Chair glissante", "descEn": "Better chance to escape hooks and bear traps.", "descEs": "Más posibilidades de escapar de ganchos y cepos.", "es": "Carne resbaladiza"}, {"id": "smallGame", "name": "Small Game", "side": "survivor", "img": "data:image/png;base64,", "desc": "T'alerte quand tu regardes vers un totem proche.", "fr": "Gibier", "descEn": "Warns you when you look toward a nearby totem.", "descEs": "Te avisa cuando miras hacia un tótem cercano.", "es": "Presa pequeña"}, {"id": "spineChill", "name": "Spine Chill", "side": "survivor", "img": "data:image/png;base64,", "desc": "Te prévient quand le tueur t'approche en te regardant et accélère tes actions.", "fr": "Frisson", "descEn": "Warns you when the killer approaches looking at you, and speeds up your actions.", "descEs": "Te avisa cuando el asesino se acerca mirándote y acelera tus acciones.", "es": "Escalofrío"}, {"id": "sprintBurst", "name": "Sprint Burst", "side": "survivor", "img": "data:image/png;base64,", "desc": "Cours à 150% de vitesse pendant 3 s au démarrage d'une course (te rend Épuisé).", "fr": "Sprint", "descEn": "Run at 150% speed for 3s when you start running (causes Exhausted).", "descEs": "Corre al 150% de velocidad durante 3s al empezar a correr (causa Agotado).", "es": "Arranque de velocidad"}, {"id": "streetwise", "name": "Streetwise", "side": "survivor", "img": "data:image/png;base64,", "desc": "Augmente l'efficacité de ton objet pour toi et les survivants proches.", "fr": "Débrouillardise", "descEn": "Increases your item's efficiency for you and nearby survivors.", "descEs": "Aumenta la eficacia de tu objeto para ti y los supervivientes cercanos.", "es": "Sabiduría callejera"}, {"id": "thisIsNotHappening", "name": "This Is Not Happening", "side": "survivor", "img": "data:image/png;base64,", "desc": "Zones de skill check agrandies quand tu es blessé.", "fr": "C'est pas vrai", "descEn": "Larger skill-check zones while you're injured.", "descEs": "Zonas de prueba de habilidad más grandes estando herido.", "es": "Esto no está pasando"}, {"id": "unbreakable", "name": "Unbreakable", "side": "survivor", "img": "data:image/png;base64,", "desc": "Te permet de te relever seul une fois quand tu es à terre.", "fr": "Increvable", "descEn": "Lets you recover from the dying state on your own once.", "descEs": "Te permite levantarte solo una vez estando en el suelo.", "es": "Irrompible"}, {"id": "urbanEvasion", "name": "Urban Evasion", "side": "survivor", "img": "data:image/png;base64,", "desc": "Tu te déplaces beaucoup plus vite en étant accroupi.", "fr": "Évasion urbaine", "descEn": "You move much faster while crouching.", "descEs": "Te mueves mucho más rápido agachado.", "es": "Evasión urbana"}, {"id": "wellMakeIt", "name": "We'll Make It", "side": "survivor", "img": "data:image/png;base64,", "desc": "Gros bonus de vitesse de soin juste après avoir décroché quelqu'un.", "fr": "On va y arriver", "descEn": "Big healing-speed bonus right after unhooking someone.", "descEs": "Gran bono de velocidad de curación justo después de descolgar a alguien.", "es": "Lo lograremos"}, {"id": "windowsOfOpportunity", "name": "Windows of Opportunity", "side": "survivor", "img": "data:image/png;base64,", "desc": "Révèle en permanence les palettes et fenêtres autour de toi.", "fr": "Fenêtres d'opportunité", "descEn": "Permanently reveals pallets and windows around you.", "descEs": "Revela permanentemente las paletas y ventanas a tu alrededor.", "es": "Ventana de oportunidad"}];
